ckground-color: vars.$lightColor;\r\n                    font-family: vars.$mainFontFamily;\r\n                    font-weight: vars.$mainFontWeightMedium;\r\n                }\r\n            }\r\n            &-text{\r\n                color: vars.$greyColor;\r\n                text-align: justify;\r\n                font-size: 1.5rem;\r\n                line-height: 1.2;\r\n            }\r\n            & > .btn{\r\n                margin: 2rem 2rem;\r\n            }\r\n\r\n\r\n\r\n            &--popular{\r\n                position: relative;\r\n                &::before{\r\n                    text-align: center;\r\n                    vertical-align: middle;\r\n                    width: 80%;\r\n                    font-family: vars.$mainFontFamily;\r\n                    font-weight: vars.$mainFontWeightBold;\r\n                    color: vars.$secondaryColor;\r\n                    font-size: 1.5rem;\r\n                    position: absolute;\r\n                    top: 0;\r\n                    right: 50%;\r\n                    translate: 50% -90%;\r\n                    background-color: #fff;\r\n                    padding: 1rem 0;\r\n                    border-radius: 1em 1em 0 0;\r\n                    border: 1px solid vars.$borderColor;\r\n                    z-index: 0;\r\n                    content: '• КЛИЕНТЫ ВЫБИРАЮТ •'\r\n                }\r\n            }\r\n        }\r\n\r\n        @include m.tablet{\r\n            padding-block: 3rem;\r\n\r\n            & > .wrapper{\r\n                padding-block: 3rem;\r\n                flex-direction: column;\r\n                align-items: stretch;\r\n                gap: 1.6rem;\r\n            }\r\n\r\n            &__title{\r\n                margin-bottom: 3rem;\r\n            }\r\n\r\n            &__card{\r\n                min-width: 100%;\r\n                max-width: 100%;\r\n                margin: 0;\r\n\r\n                &-header{\r\n                    padding: 2.2rem 1.2rem;\r\n\r\n                    & > img{\r\n                        width: 13rem;\r\n                        margin-left: 0;\r\n                    }\r\n\r\n                    & > .payment-systems{\r\n                        & > img{\r\n                            width: 8rem;\r\n                            margin-right: 0;\r\n                        }\r\n                    }\r\n                }\r\n\r\n                &-info{\r\n                    padding: 1rem 1.6rem;\r\n                }\r\n\r\n                & > .btn{\r\n                    margin: 1.6rem;\r\n                }\r\n            }\r\n        }\r\n\r\n        @include m.mobile{\r\n            padding-block: 2rem 3rem;\r\n\r\n            & > .wrapper{\r\n                padding-block: 2rem;\r\n                gap: 1.2rem;\r\n            }\r\n\r\n            &__title{\r\n                margin-bottom: 2rem;\r\n                font-size: vars.$h3Size;\r\n                text-wrap: balance;\r\n            }\r\n\r\n            &__card{\r\n                border-radius: 1.6rem;\r\n\r\n                &-header{\r\n                    border-radius: 1.6rem 1.6rem 0 0;\r\n                    padding: 1.6rem 1rem;\r\n\r\n                    & > img{\r\n                        width: 11rem;\r\n                    }\r\n\r\n                    & > .payment-systems{\r\n                        & > img{\r\n                            width: 7rem;\r\n                        }\r\n                    }\r\n                }\r\n\r\n                &-info{\r\n                    gap: 1rem;\r\n                    padding: 1rem 1.2rem;\r\n                }\r\n\r\n                &-list{\r\n                    & > li{\r\n                        margin: 0.3rem 0.2em;\r\n                        padding: 0.45rem 0.9rem;\r\n                    }\r\n                }\r\n\r\n                &--popular{\r\n                    &::before{\r\n                        width: 88%;\r\n                        font-size: 1.3rem;\r\n                        padding: 0.8rem 0;\r\n                    }\r\n                }\r\n\r\n                & > .btn{\r\n                    width: calc(100% - 2.4rem);\r\n                    margin: 1.2rem;\r\n                }\r\n            }\r\n        }\r\n    }\r\n    &-process{\r\n        display: flex;\r\n        flex-flow: row wrap;\r\n        justify-content: space-around;\r\n        gap: 2rem;\r\n        &__info{\r\n            // outline: 1px dashed plum;\r\n            max-width: 50%;\r\n        }\r\n        &__title{\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightSemibold;\r\n            margin: 8rem auto;\r\n            color: vars.$darkColor;\r\n        }\r\n        &__subtitle{\r\n            font-size: 2rem;\r\n            padding: 1rem 1rem 0 1rem;\r\n        }\r\n\r\n        @include m.tablet{\r\n            padding-block: 3rem;\r\n            flex-direction: column;\r\n            align-items: stretch;\r\n            gap: 2.4rem;\r\n\r\n            &__title{\r\n                margin: 4rem auto 0;\r\n                text-align: center;\r\n            }\r\n\r\n            &__info{\r\n                max-width: 100%;\r\n            }\r\n\r\n            &__subtitle{\r\n                padding: 0;\r\n            }\r\n\r\n            &__container{\r\n                max-width: 100%;\r\n                width: 100%;\r\n            }\r\n        }\r\n\r\n        @include m.mobile{\r\n            padding-block: 2rem 3rem;\r\n            gap: 2rem;\r\n\r\n            &__title{\r\n                margin: 2rem auto 0;\r\n            }\r\n\r\n            &__subtitle{\r\n                font-size: 1.8rem;\r\n                text-align: center;\r\n            }\r\n\r\n            .bankcards-advantages{\r\n                padding-block: 1rem;\r\n                gap: 1.2rem;\r\n            }\r\n\r\n            .advantage-card{\r\n                margin: 0;\r\n                padding: 1.8rem;\r\n                gap: 1.4rem;\r\n            }\r\n        }\r\n    }\r\n}\r\n\r\n\r\n// Accounting Services\r\n.accounting{\r\n    &-details{\r\n        display: flex;\r\n        flex-flow: row wrap;\r\n        justify-content: space-around;\r\n        padding-block: 5rem;\r\n        gap: 4rem;\r\n        & > ul{ & > li{font-size: 5rem}}\r\n        &__title{\r\n            width: 100%;\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightMedium;\r\n            text-align: center;\r\n            margin-bottom: 3rem;\r\n        }\r\n        &__text{\r\n            text-align:justify; \r\n            border: 1px solid #fff;\r\n            background-color: #ffffff9c;\r\n            border-radius: 2rem;\r\n            backdrop-filter: blur(12px);\r\n            padding: 2rem;\r\n            line-height: 1.33;\r\n\r\n        }\r\n        & > .service-card--base{\r\n            max-width: 48%;\r\n            @include m.mobile{\r\n                max-width: 100%;\r\n            }\r\n        }\r\n        @include m.mobile{\r\n            gap: 1rem;\r\n        }\r\n    }\r\n    &-process{\r\n        display: flex; flex-direction: column;\r\n        gap: 10rem;\r\n        padding-block: 5rem;\r\n        &__title{\r\n            text-align: center;\r\n        }\r\n        & > .scheme-container{\r\n            max-width: 100%;\r\n        }\r\n        @include m.mobile{\r\n            gap: 3rem;\r\n            padding-block-start: 1rem;\r\n        }\r\n    }\r\n    &__price-tag{\r\n        width: 100%;\r\n        text-align: start;\r\n    }\r\n\r\n    &-animation{\r\n        &-pos1{\r\n            top:700px\r\n        }\r\n        &-pos2{\r\n            top:1550px;\r\n        }\r\n    }\r\n    @include m.mobile{\r\n        &__price-tag{\r\n            text-align: center;\r\n            text-shadow: 0 0 4px vars.$lightColor;\r\n            font-size: vars.$h5Size;\r\n        }\r\n        &-details{\r\n            &__title{\r\n                margin: 0 0 1rem 0;\r\n            }\r\n        }\r\n    }\r\n}\r\n\r\n.bg-geometry{\r\n    position: absolute;\r\n    right: -360px;\r\n    height: 350px;\r\n    min-width: 350px;\r\n    border-radius: 2rem;\r\n    background: linear-gradient(\r\n        45deg,\r\n        vars.$primaryColor,\r\n        vars.$secondaryColor\r\n    );\r\n}\r\n.bg-geometry-2{\r\n    translate: -100% 0;\r\n    left: 0;\r\n    position: absolute;\r\n    height: 350px;\r\n    min-width: 350px;\r\n    border-radius: 2rem;\r\n    background: linear-gradient(\r\n        45deg,\r\n        vars.$primaryColor,\r\n        vars.$secondaryColor\r\n    );\r\n}\r\n\r\n.bg-geometry-cubeBase{\r\n    position: absolute;\r\n    top: 0;\r\n    width: 250px;\r\n    height: 700px;\r\n    border-radius: 2rem;\r\n    background: linear-gradient(\r\n        45deg,\r\n        vars.$primaryColor,\r\n        vars.$secondaryColor\r\n    );\r\n}\r\n\r\n\r\n\r\n// REGISTRATION\r\n.registration{\r\n    &-details{\r\n    display: flex;\r\n    flex-direction: column;\r\n    gap: 10rem;\r\n    padding-block: 5rem;\r\n        & > .scheme-container--horizontal{\r\n            max-width: 100%;\r\n        }\r\n        &__title{\r\n            text-align: center;\r\n        }\r\n\r\n        @include m.tablet{\r\n            gap: 2.6rem;\r\n            padding-block: 3rem;\r\n        }\r\n\r\n        @include m.mobile{\r\n            gap: 1.8rem;\r\n            padding-block: 2rem 3rem;\r\n\r\n            &__title{\r\n                text-wrap: balance;\r\n            }\r\n        }\r\n    }\r\n    &-methods{\r\n        padding-block: 5rem;\r\n        display: flex;\r\n        gap: 2rem;\r\n\r\n        @include m.tablet{\r\n            padding-block: 3rem;\r\n            display: grid;\r\n            grid-template-columns: 1fr;\r\n            gap: 1.6rem;\r\n\r\n            & > .service-card{\r\n                margin: 0;\r\n                width: 100%;\r\n                min-width: 0;\r\n                height: auto;\r\n                padding: 2.4rem;\r\n            }\r\n\r\n            .service-card__header{\r\n                grid-template-columns: 72px minmax(0, 1fr);\r\n                grid-template-areas:\r\n                    \"price price\"\r\n                    \"timeline timeline\"\r\n                    \"icon title\";\r\n                column-gap: 1.2rem;\r\n                row-gap: 0.6rem;\r\n                align-items: start;\r\n            }\r\n\r\n            .service-card__price-tag,\r\n            .service-card__timeline-tag{\r\n                position: static;\r\n                right: auto;\r\n                text-shadow: none;\r\n            }\r\n\r\n            .service-card__price-tag{\r\n                grid-area: price;\r\n                justify-self: start;\r\n            }\r\n\r\n            .service-card__timeline-tag{\r\n                grid-area: timeline;\r\n                justify-self: start;\r\n                translate: none;\r\n            }\r\n\r\n            .service-card__icon{\r\n                grid-area: icon;\r\n            }\r\n\r\n            .service-card__title{\r\n                grid-area: title;\r\n                margin: 0;\r\n                align-self: center;\r\n                min-width: 0;\r\n                overflow-wrap: anywhere;\r\n            }\r\n        }\r\n\r\n        @include m.mobile{\r\n            padding-block: 2rem 3rem;\r\n            gap: 1.2rem;\r\n\r\n            & > .service-card{\r\n                padding: 2rem;\r\n            }\r\n\r\n            .service-card__header{\r\n                grid-template-columns: 64px minmax(0, 1fr);\r\n                column-gap: 1rem;\r\n                row-gap: 0.4rem;\r\n            }\r\n\r\n            .service-card__price-tag,\r\n            .service-card__timeline-tag{\r\n                font-size: 1.4rem;\r\n            }\r\n\r\n            .service-card__icon{\r\n                width: 64px;\r\n                padding: 1.4rem;\r\n                border-radius: 1.2rem;\r\n            }\r\n\r\n            .service-card__cta > .btn{\r\n                width: 100%;\r\n            }\r\n        }\r\n    }\r\n}\r\n\r\n\r\n//playground\r\n.sandbox{\r\n    height: 600vh; \r\n    display: flex; flex-flow: row wrap;\r\n    align-content: flex-start;\r\n    justify-content: space-between;\r\n    padding: 10rem; \r\n    border: 1px dashed rgb(141, 176, 216); \r\n    border-radius: 2rem; \r\n    margin-bottom: 2rem;\r\n}\r\n.playground-box{\r\n    width: 85px;\r\n    height: 85px;\r\n    background: radial-gradient(\r\n        #1596d1,\r\n        #4740aa\r\n    );\r\n    border-radius: 2em;\r\n    margin: 1rem 0.5rem;\r\n}\r\n\r\n.bg-animations{\r\n    height: 10px;\r\n    width: 100%;\r\n    position: relative;\r\n    overflow-x: clip;\r\n    z-index: -10;\r\n}\r\n\r\n\r\n//maintenance\r\n\r\n.maintenance{\r\n    &-container{\r\n        // outline: 2px dashed salmon;\r\n        height: 100vh;\r\n        display: flex;\r\n        flex-direction: column;\r\n        justify-content: space-between;\r\n    }\r\n    &__logo{\r\n        align-self: flex-start;\r\n        margin-top: 2rem;\r\n        width: 200px;\r\n        display: flex;\r\n        margin-inline: auto;\r\n    }\r\n    &__title{\r\n        text-align: center;\r\n        margin: 1rem 0;\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightBold;\r\n        @include m.mobile{\r\n            font-size: 3rem;\r\n            margin-bottom: 4rem;\r\n        }\r\n    }\r\n    &__subtitle{\r\n        text-align: center;\r\n        margin: 1rem 0;\r\n\r\n        @include m.mobile{\r\n            font-size: 1.4rem;\r\n\r\n        }\r\n    }\r\n    &__mid{\r\n        & > h5{\r\n            margin-top: 2rem;\r\n        }\r\n    }\r\n    &__end{\r\n        text-align: center;\r\n        margin-bottom: 3rem;\r\n    }\r\n    &__bg-design{\r\n        position: absolute;\r\n        z-index: -100;\r\n        height: 100vh;\r\n        width: 100vw;\r\n        overflow: hidden;\r\n        &__item{\r\n            position: absolute;\r\n            width: 700px;\r\n            height: 700px;\r\n            background: radial-gradient(vars.$primaryColor, vars.$secondaryColor 70%);\r\n            border-radius: 100%;\r\n            &:nth-child(1) {\r\n                top: -400px;\r\n                left: -300px;\r\n            }\r\n            &:nth-child(2) {\r\n                position: absolute;\r\n                right: -380px;\r\n                bottom: -380px;;\r\n                // translate: 30% 30%;\r\n            }\r\n        }\r\n    }\r\n    &__contact-links{\r\n        margin-top: 3rem;\r\n        display: flex;\r\n        justify-content: space-around;\r\n        & > ul {\r\n            background-color: #fff;\r\n            border: 1px solid vars.$borderColor;\r\n            padding: 2rem;\r\n            border-radius: 2rem;\r\n            & > p{\r\n                margin-bottom: 1rem;\r\n            }\r\n        }\r\n    }\r\n    &__lang-switcher{\r\n        right: 0;\r\n        position: absolute;\r\n        display: flex;\r\n        justify-content: center;\r\n        & > button{\r\n            margin: 1rem;\r\n            & > img{\r\n                margin-left: 1rem;\r\n            }\r\n        }\r\n    }\r\n}\r\n.sassafras{\r\n    padding: 2rem 0 0 0;\r\n}\r\n\r\n\r\n// ABOUT-US & STAFF\r\n\r\n.about-us-page{\r\n    @include m.mobile{\r\n        & > .hero--aboutus,\r\n        & > .staff,\r\n        & > .reviews,\r\n        & > .contact{\r\n            padding-inline: 2rem;\r\n        }\r\n    }\r\n}\r\n\r\n.staff{\r\n    display: flex;\r\n    flex-wrap: wrap;\r\n    padding-block: 5rem;\r\n    gap: 3rem;\r\n    background: linear-gradient(\r\n        180deg,\r\n        #DFEDFF,\r\n        #ffffff\r\n    ); \r\n    &__header{\r\n        width: 100%;\r\n        text-align: center;\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightSemibold;\r\n    }\r\n    &-container{\r\n        display: flex;\r\n        flex-flow: row wrap;\r\n        justify-content: space-around;\r\n        gap: 3.5rem;\r\n        @extend .wrapper;\r\n        padding: 0;\r\n    }\r\n    &-card{\r\n        width: 290px;\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 1.5rem;\r\n        outline: 1px solid vars.$borderColor;\r\n        padding: 2rem;\r\n        border-radius: 3rem;\r\n        background-color: #ffffff7a;\r\n        &__header{\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightSemibold;\r\n            text-align: center;    \r\n        }\r\n        &__position{\r\n            text-align: center;\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightMedium;\r\n        }\r\n        &__photo{\r\n            width: 250px;\r\n            border-radius: 2rem;\r\n        }\r\n    }\r\n\r\n    @include m.mobile{\r\n        gap: 2rem;\r\n        padding-block: 3rem;\r\n\r\n        &-container{\r\n            gap: 2rem;\r\n            justify-content: center;\r\n        }\r\n\r\n        &-card{\r\n            width: 100%;\r\n            max-width: 29rem;\r\n            padding: 1.6rem;\r\n\r\n            &__photo{\r\n                width: 100%;\r\n                max-width: 25rem;\r\n                align-self: center;\r\n            }\r\n        }\r\n    }\r\n}\r\n\r\n// CONTACTS PAGE\r\n\r\n.extra-details{\r\n    display: flex;\r\n    justify-content: space-between;\r\n    flex-flow: row wrap;\r\n    gap: 3rem;\r\n    padding-block-end: 10rem;\r\n    &__text{\r\n        text-align: center;\r\n    }\r\n    &__container{\r\n        // outline: 1px dashed salmon;\r\n        width: 48%;\r\n        display: flex;\r\n        flex-flow:column wrap;\r\n        align-items: center;\r\n        gap: 3rem;\r\n        &-item{\r\n            display: flex;\r\n            flex-direction: column;\r\n            align-items: center;\r\n            gap: 1rem;\r\n        }\r\n        &-wrapper{\r\n            display: flex;\r\n            justify-content: space-around;\r\n            width: 100%;\r\n            // outline: 1px dashed pink;\r\n            margin: 0 auto;\r\n        }\r\n        & > h3, h5{\r\n            text-align: center;\r\n        }\r\n        & > video{\r\n            display: block;\r\n            width: 100%;\r\n            height: auto;\r\n            aspect-ratio: 1920 / 1080;\r\n            border-radius: 1rem;\r\n            border: 2px solid vars.$primaryColor;  \r\n        }\r\n    }\r\n    &__iframe{\r\n        border-radius: 1rem;\r\n        border: 2px solid vars.$primaryColor; \r\n        width: 100%;\r\n        min-height: 337px;\r\n\r\n    }\r\n    &__map-link{\r\n        background-color: #ffffffcb;\r\n        gap: 2rem;\r\n        display: flex;\r\n        flex-direction: column;\r\n        font-size: vars.$h4Size;\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightSemibold;\r\n        text-align: center;\r\n        padding: 2rem;\r\n        transition: 0.23s;\r\n        border-radius: 1rem;\r\n        border: 1px solid vars.$borderColor;\r\n        // border: 1px solid #fff;\r\n        &:hover{\r\n            box-shadow: 0 0 20px vars.$lightColor;\r\n            scale: 1.05;\r\n            border: 1px solid #fff;\r\n        }\r\n    }\r\n    &__map-image{\r\n        width: 70px;\r\n        height: 70px;\r\n        display: block;\r\n        align-self: center;\r\n        margin-inline: auto;\r\n    }\r\n\r\n    @include m.tablet{\r\n        gap: 3rem;\r\n        padding-block-end: 6rem;\r\n\r\n        &__container{\r\n            width: 100%;\r\n            gap: 2rem;\r\n            & > video{\r\n                width: 100%;\r\n            }\r\n        }\r\n\r\n        // &__iframe{\r\n        //     min-height: 34rem;\r\n        // }\r\n\r\n        &__map-link{\r\n            font-size: 2rem;\r\n            padding: 1.6rem;\r\n        }\r\n\r\n        &__map-image{\r\n            width: 60px;\r\n            height: 60px;\r\n        }\r\n    }\r\n\r\n    @include m.mobile{\r\n        gap: 2rem;\r\n        padding-block-end: 4rem;\r\n\r\n        &__container{\r\n            gap: 1.6rem;\r\n            & > video{\r\n                width: 100%;\r\n            }\r\n        }\r\n\r\n        &__text{\r\n            text-align: start;\r\n        }\r\n\r\n        &__iframe{\r\n            height: 20rem;\r\n        }\r\n\r\n        &__map-link{\r\n            width: 100%;\r\n            font-size: 1.8rem;\r\n            padding: 1.2rem;\r\n            gap: 1rem;\r\n        }\r\n\r\n        &__map-image{\r\n            width: 52px;\r\n            height: 52px;\r\n        }\r\n    }\r\n}\r\n\r\n// REVIEWS\r\n\r\n.reviews{\r\n    padding-block: 3rem 10rem;\r\n    &__title, &__text{\r\n        text-align:center;\r\n        margin: 2rem;\r\n    }\r\n    &__text{\r\n        line-height: 1.3;\r\n    }\r\n    &__title{\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightMedium;\r\n    }\r\n    \r\n    @include m.mobile{\r\n        &__title{\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightSemibold;\r\n        }\r\n    }\r\n\r\n}\r\n\r\n// SWIPER\r\n\r\n.swiper{\r\n    height: 35rem;\r\n    width: 80%;\r\n    &-slide{\r\n        display: flex;\r\n        justify-content: center;\r\n        align-items: center;\r\n        font-size: vars.$h3Size;\r\n        font-family: vars.$mainFontRegular;\r\n        border-radius: 2rem;\r\n        &__card{\r\n            background-color: #fff;\r\n            width: 70%;\r\n            padding: 2rem;\r\n            display: flex;\r\n            flex-flow: row wrap;\r\n            justify-content: flex-start;\r\n            border: 1px solid vars.$borderColor;\r\n            border-radius: 1.5rem;\r\n            box-shadow: 0px 0px 15px vars.$blueShadowColor;\r\n            & > header{\r\n                display: flex;\r\n                flex-direction: column;\r\n                justify-content: center;\r\n                align-items: flex-start;\r\n                // outline: 1px solid red;\r\n                gap: 1rem;\r\n            }\r\n            &-name{\r\n                font-family: vars.$mainFontFamily;\r\n                font-weight: vars.$mainFontWeightSemibold;\r\n            }\r\n            &-date{\r\n                font-family: vars.$mainFontFamily;\r\n                font-weight: vars.$mainFontWeightMedium;\r\n            }\r\n            &-stars{\r\n                left: 0;\r\n                // outline: 1px solid rgb(136, 160, 49);\r\n                height: 30px;\r\n                // width: 80%;\r\n                content: url(/src/graphics/svg/card-stars.svg);\r\n            }\r\n            &-image{\r\n                width: 100px;\r\n                height: 100px;\r\n                margin: 2rem;\r\n                border-radius: 100%;\r\n                border: 1px solid vars.$borderColor;\r\n            }\r\n            &-text{\r\n                margin: 1rem 2rem;\r\n            }\r\n        }\r\n    }\r\n    &-button-next, &-button-prev{\r\n        border-radius: 100%;\r\n        transition: 0.33s;\r\n        &:hover{\r\n            scale: 1.2;\r\n            filter: brightness(1.5);\r\n        }\r\n    }\r\n    \r\n    @include m.mobile{\r\n        height: 60rem;\r\n        width: 100%;\r\n        &-button-next, &-button-prev{\r\n            scale: 0.3;\r\n            &:hover{\r\n                scale: 0.7;\r\n            }\r\n        }\r\n        &-slide{\r\n            &__card{\r\n                width: 100%;\r\n                min-height: 40rem;\r\n                &-image, &-name, &-date, &-stars, & > header{\r\n                    margin: auto;\r\n                    text-align: center;\r\n                }\r\n                &-text{\r\n                    margin: 2rem 2rem;\r\n                    text-align: justify;\r\n                }\r\n            }\r\n        }\r\n    }\r\n}\r\n\r\n.accounting-illustration__part-2{\r\n    position: absolute;\r\n}\r\n\r\n.accounting-illustration__part-6-mask{\r\n    --accounting-sidebar-clip-y: 0.5rem;\r\n    --accounting-sidebar-clip-tilt: 15rem;\r\n    position: absolute;\r\n    inset: 0;\r\n    overflow: hidden;\r\n    // border: 1px solid red;\r\n    clip-path: polygon(\r\n        0 calc(var(--accounting-sidebar-clip-y) + var(--accounting-sidebar-clip-tilt)),\r\n        100% var(--accounting-sidebar-clip-y),\r\n        100% 30%,\r\n        0 66.5%\r\n    );\r\n\r\n    & > .accounting-illustration__part-6{\r\n        position: absolute;\r\n        inset: 0;\r\n        width: 100%;\r\n        height: 100%;\r\n    }\r\n}\r\n\r\n@media (max-width: 1439px){\r\n    .accounting-illustration__part-6-mask{\r\n        --accounting-sidebar-clip-y: 0.35rem;\r\n        --accounting-sidebar-clip-tilt: clamp(6rem, 14vw, 11rem);\r\n    }\r\n}\r\n\r\n@include m.tablet{\r\n    .accounting-illustration__part-6-mask{\r\n        --accounting-sidebar-clip-y: 3rem;\r\n        --accounting-sidebar-clip-tilt: clamp(4.5rem, 18vw, 8rem);\r\n    }\r\n}\r\n\r\n@include m.mobile{\r\n    .accounting-illustration__part-6-mask{\r\n        --accounting-sidebar-clip-y: 2.3rem;\r\n        --accounting-sidebar-clip-tilt: clamp(3.5rem, 24vw, 6rem);\r\n    }\r\n}\r\n"]}
