ute;\r\n            right: 1rem;\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightBold;\r\n            text-transform: uppercase;\r\n            content: \"#434c5b\";\r\n        }\r\n    }\r\n    &_lightgrey-color{\r\n        background-color: vars.$lightGreyColor;\r\n        color: vars.$white;\r\n        &::after{\r\n            position: absolute;\r\n            right: 1rem;\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightBold;\r\n            text-transform: uppercase;\r\n            content: \"#646d83\";\r\n        }\r\n    }\r\n}\r\n.alert-text{\r\n    color: red !important;\r\n}\r\n\r\n.divider {\r\n    height: 20px;\r\n}\r\n\r\n.backer{\r\n        position: fixed;\r\n        right: 0;\r\n        bottom: 0;\r\n        height: 70px;\r\n        width: 70px;\r\n        border-radius: 100%;\r\n        margin: 2.5rem;\r\n        background-color: #e7effea2;;\r\n        padding: 1rem 0;\r\n\r\n        & > a{\r\n            font-size: 5rem;\r\n            font-weight: 900;\r\n            color: vars.$primaryColor;\r\n            & > img{\r\n                display: flex;\r\n                margin : auto;\r\n                height: 50px;\r\n                width: 50px;\r\n                // outline: 1px solid red;\r\n                border-radius: 100%;\r\n            }\r\n        }\r\n\r\n        &:hover{\r\n            background-color: vars.$primaryColor;\r\n            & > a{\r\n                & > img{\r\n                    filter: brightness(100);\r\n                }\r\n            }\r\n        }\r\n\r\n        @include m.tablet{\r\n            z-index: 200;\r\n            height: 60px;\r\n            width: 60px;\r\n\r\n            & > a{\r\n                & > img{\r\n                    height: 40px;\r\n                    width: 40px;\r\n                }\r\n            }\r\n        }\r\n        @include m.mobile{\r\n            margin-right: 2.5rem;\r\n            height: 70px;width: 70px;\r\n            & > a{\r\n                & >img{\r\n                height: 47px;width: 47px;\r\n                }\r\n            }\r\n        }\r\n    }\r\n\r\n\r\n\r\n.wrapper {\r\n    // outline: 1px dashed darksalmon;\r\n    margin: 0 auto;\r\n    max-width: 1280px;\r\n    &--wided{\r\n        max-width:1800px;\r\n    }\r\n    @include m.tablet{\r\n        padding: 0 2rem;\r\n    }\r\n    @include m.desktop{\r\n        padding: 0 3rem;\r\n    }\r\n\r\n}\r\n\r\n.badge {\r\n    top: -30%;\r\n    left: 50%;\r\n    transform: translateX(-50%);\r\n    position: absolute;\r\n    padding: 1.3rem 3rem;\r\n    background-color: vars.$lightColor;\r\n    border-radius: 3em;\r\n    font-size: vars.$badgeFontSize;\r\n    font-family: vars.$mainFontFamily;\r\n    font-weight: vars.$mainFontWeightBold;\r\n    color: vars.$primaryColor;\r\n    text-transform: uppercase;\r\n}\r\n\r\n// Exclusive Offer Badge\r\n.exclusive-offer{\r\n    display: grid;\r\n    position: relative;\r\n    padding-block: 15rem;\r\n    gap: 9rem;\r\n    &__header{\r\n        position: relative;\r\n    }\r\n    &__title{\r\n        text-align: center;\r\n    }\r\n    &__badge{\r\n        @extend .badge;\r\n        top: 0;\r\n        padding: 1rem 3rem;\r\n        font-size: 1.3rem;\r\n        &::before {\r\n            vertical-align: middle;\r\n            content: url(/src/graphics/png/exclusive-badge-before.png);\r\n            margin-right: 1rem;\r\n        }\r\n    }\r\n    &__cards {\r\n        display: grid;\r\n        grid-template-columns: 1fr 1fr 1fr;\r\n        grid-template-rows: auto auto auto;\r\n        grid-template-areas:\r\n            \"main tax transfer\"\r\n            \"main months reports\"\r\n            \"main cta cta\";\r\n        gap:2.4rem;\r\n        column-gap: 4rem;\r\n    }\r\n}\r\n\r\n#main {grid-area: main; min-width: 600px;}\r\n#tax {grid-area: tax;}\r\n#transfer {grid-area: transfer;}\r\n#months {grid-area: months;}\r\n#reports {grid-area: reports;}\r\n#cta {grid-area: cta;}\r\n\r\n// Services\r\n.services {\r\n    display: flex;\r\n    flex-direction: column;\r\n    padding-block: 10rem;\r\n    gap: 3rem;\r\n    \r\n    &__title, &__subtitle {text-align: center}\r\n    &__subtitle {\r\n        color: vars.$greyColor;\r\n    }\r\n    &__header {\r\n        position: relative;\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 3rem;\r\n    }\r\n    &__badge{\r\n        @extend .badge;\r\n    }\r\n\r\n    &__grid{\r\n        --min: 800px;\r\n        display: grid;\r\n        gap: 2.5rem 3rem;\r\n        grid-template-columns:  repeat(auto-fit, minmax(var(--min), 1fr));\r\n        align-items: stretch;\r\n    }\r\n\r\n    @media (min-width: 1024px) and (max-width: 1689px){\r\n        &__grid{\r\n            grid-template-columns: repeat(2, minmax(0, 1fr));\r\n        }\r\n    }\r\n\r\n    .service-card__icon{\r\n        order: -1;\r\n    }\r\n\r\n    @include m.tablet{\r\n        &__title{\r\n            font-size: 4.6rem;\r\n            line-height: 1.08;\r\n            text-wrap: balance;\r\n        }\r\n        &__subtitle{\r\n            // font-size: 1.8rem;\r\n            line-height: 1.35;\r\n        }\r\n        &__grid{\r\n            --min: 100%;\r\n            gap: 2rem;\r\n        }\r\n        .service-card{\r\n            padding: 2.4rem;\r\n\r\n            &__icon{\r\n                order: 0;\r\n            }\r\n        }\r\n        &__badge{\r\n            width: 70%;\r\n            text-align: center;\r\n        }\r\n    }\r\n\r\n    @include m.mobile{\r\n        padding-block-end: 3rem;\r\n        &__header{\r\n            gap: 1rem;\r\n        }\r\n        &__title{\r\n            font-size: 4rem;\r\n            line-height: 1.12;\r\n            text-wrap: balance;\r\n            overflow-wrap: anywhere;\r\n        }\r\n        &__subtitle{\r\n            // font-size: 1.6rem;\r\n            line-height: 1.35;\r\n        }\r\n        .service-card{\r\n            padding: 1.7rem;\r\n            gap: 1.6rem;\r\n            &__title{\r\n                font-family: vars.$mainFontFamily;\r\n                font-weight: vars.$mainFontWeightSemibold;\r\n                text-align: center;\r\n                margin: 1rem;\r\n            }\r\n            &__header{\r\n                gap: 0.2rem;\r\n            }\r\n            &__price-tag,&__timeline-tag{\r\n                position: relative;\r\n                width: 100%;\r\n                translate: 0 0;\r\n                display: inline-flex;\r\n                line-height: 1.25;\r\n                text-align: center;\r\n                justify-content: center;\r\n                margin-bottom: 1rem;\r\n            }\r\n            &__price-tag{\r\n                justify-content: center;\r\n                margin: 1rem 0 0 0;\r\n            }\r\n            &__icon{\r\n                width: 120px;\r\n                margin: 0 auto;\r\n            }\r\n            &__benefits > li{\r\n                margin: 0.4rem 0 0.4rem 2.6rem;\r\n                line-height: 1.3;\r\n                &::before{\r\n                    translate: -2.2rem -2px;\r\n                }\r\n            }\r\n        }\r\n    }\r\n}\r\n\r\n// Logistic\r\n.logistic {\r\n    display: grid;\r\n    position: relative;\r\n    padding-block: 10rem;\r\n    gap: 4rem;\r\n    &__header{\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 3rem;\r\n    }\r\n    &__title, &__lead{\r\n        text-align: center\r\n    }\r\n    &__kpi{\r\n        display: flex;\r\n        justify-content: center;\r\n        gap: 2rem;\r\n        &-item{\r\n            margin: 0;\r\n        }\r\n        &-icon{\r\n            display: block;\r\n            margin: 0 auto;\r\n            width: 80px;\r\n            background-color: vars.$lightColor;\r\n            border-radius: 1.5rem;\r\n        }\r\n        &-score, &-caption {\r\n            text-align: center;\r\n        }\r\n        &-caption{\r\n            margin-top: 0.2rem;\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightMedium;\r\n            color: vars.$greyColor;\r\n        }\r\n    }\r\n    \r\n    &__cards{\r\n        display: grid;\r\n        grid-template-columns: 0.8fr 1fr;\r\n        gap: 2rem;\r\n    }\r\n    &__container{\r\n        display: grid;\r\n        gap: 2rem;\r\n    }\r\n\r\n    &__badge{\r\n        @extend .badge;\r\n        top: 0;\r\n    }\r\n\r\n    .service-card--logistics{\r\n        margin: 0;\r\n    }\r\n\r\n    @include m.tablet{\r\n        padding-block: 8rem;\r\n        &__title{\r\n            font-size: 4.4rem;\r\n            line-height: 1.08;\r\n            text-wrap: balance;\r\n        }\r\n        &__kpi{\r\n            flex-wrap: wrap;\r\n            justify-content: center;\r\n            gap: 1.6rem;\r\n            &-item{\r\n                flex: 1 1 calc(50% - 1.6rem);\r\n                max-width: calc(50% - 1.6rem);\r\n            }\r\n        }\r\n        &__cards{\r\n            grid-template-columns: 1fr;\r\n        }\r\n    }\r\n\r\n    @include m.mobile{\r\n        padding-block: 7rem 2rem;\r\n        gap: 3rem;\r\n        &__header{\r\n            gap: 2rem;\r\n        }\r\n        &__title{\r\n            font-size: 3.2rem;\r\n            line-height: 1.12;\r\n        }\r\n        &__lead{\r\n            font-size: vars.$h5Size * 0.8;\r\n            line-height: 1.3;\r\n        }\r\n        &__kpi{\r\n            gap: 1.2rem;\r\n            &-item{\r\n                flex-basis: 100%;\r\n            }\r\n        }\r\n        &__badge{\r\n            width: 90%;\r\n            text-align: center;\r\n        }\r\n        \r\n        .service-card{\r\n            padding: 2rem;\r\n            &__title{\r\n            // font-size: 1rem;\r\n            line-height: 1.15;\r\n            }\r\n            &__extras > li{\r\n                width: 100%;\r\n                justify-content: flex-start;\r\n                & > p{\r\n                margin-left: 1rem;\r\n                }\r\n            }\r\n        }\r\n    }\r\n}\r\n\r\n// Contact\r\n.contact {\r\n    position: relative;\r\n    display: flex;\r\n    gap: 3rem;\r\n    align-items: center;\r\n    @extend .wrapper;\r\n    padding: 0;\r\n    padding-block-end: 10rem;\r\n    & > .form{\r\n        width: 100%;\r\n    }\r\n    & > .contact__details:only-child{\r\n        max-width: none;\r\n        width: 100%;\r\n    }\r\n    &__badge{\r\n        @extend .badge;\r\n        top: 0;\r\n        left: 0;\r\n        translate: 50% -150%;\r\n    }\r\n    &__details {\r\n        position: relative;\r\n        display: flex;\r\n        flex-direction: column;\r\n        width: 80%;\r\n        justify-content: center;\r\n        gap:3rem;\r\n    }\r\n    &__title{\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightSemibold;\r\n        line-height: 1.08;\r\n        text-wrap: balance;\r\n    }\r\n    &__links {\r\n        display: flex;\r\n        flex-flow: row wrap;\r\n        column-gap: 5rem;\r\n        row-gap: 1.8rem;\r\n        & > ul {\r\n            margin-bottom: 0;\r\n            & > p {\r\n                margin-bottom: 1rem;\r\n            }\r\n        }\r\n        &--maintenance{\r\n            column-gap: 1rem;\r\n            justify-content: space-between;\r\n            & > ul{\r\n                border: 1px solid vars.$borderColor;\r\n                height: auto;\r\n                padding: 2rem;\r\n                border-radius: 2rem;\r\n            }\r\n            & > .contact__addresses{\r\n                width: 35%;\r\n            }\r\n        }\r\n    }\r\n    &__subtitle{\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightSemibold;\r\n        line-height: 1.25;\r\n    }\r\n    &__text{\r\n        color: vars.$darkColor;\r\n        line-height: 1.35;\r\n    }\r\n\r\n    &__mails > li, &__phones > li, &__socials > li{\r\n        font-family: vars.$mainFontRegular;\r\n        font-size: vars.$pSize;\r\n        min-width: 0;\r\n    }\r\n    &__mails {\r\n        & > li {\r\n            display: flex;\r\n            align-items: flex-start;\r\n            gap: 0.7rem;\r\n            margin-bottom: 0.5rem;\r\n            color:vars.$darkColor;\r\n            text-decoration: underline;\r\n            &::before{\r\n                display: block;\r\n                margin-right: 0;\r\n                flex: 0 0 30px;\r\n                width: 30px;\r\n                content: url(/src/graphics/svg/mail-icon.svg);\r\n            }\r\n        }\r\n    }\r\n    &__phones {\r\n        & > li {\r\n            display: flex;\r\n            align-items: flex-start;\r\n            gap: 0.7rem;\r\n            margin-bottom: 0.5rem;\r\n            color:vars.$darkColor;\r\n            text-decoration: underline;\r\n            &::before{\r\n                display: block;\r\n                margin-right: 0;\r\n                flex: 0 0 30px;\r\n                width: 30px;\r\n                content: url(/src/graphics/svg/phone-icon.svg);\r\n            }\r\n        }\r\n    }\r\n    &__socials {\r\n        & > li{\r\n            display: inline-block;\r\n            margin-top: 1rem;\r\n            margin-right: 0.5rem;\r\n        }\r\n        &--centered{ \r\n            & > div{\r\n                display: flex;\r\n                justify-content: space-around;\r\n            }\r\n        }\r\n    }\r\n\r\n    &__link{\r\n    margin: auto 0;\r\n    color: vars.$darkColor;\r\n    vertical-align: middle;\r\n    min-width: 0;\r\n    overflow-wrap: anywhere;\r\n    word-break: break-word;\r\n    line-height: 1.35;\r\n        &--arm{\r\n            &::after{\r\n                margin-left: 1rem;\r\n                vertical-align: middle;\r\n                content: url(/src/graphics/png/contact-after-tel-arm-icon.png);\r\n            }\r\n        }\r\n        &--rus{\r\n            &::after{\r\n                right: 0;\r\n                margin-left: 1rem;\r\n                vertical-align: middle;\r\n                content: url(/src/graphics/png/contact-after-tel-rus-icon.png);\r\n            }\r\n        }\r\n        &--map{\r\n            display: inline;\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightMedium;\r\n            &::before{\r\n                content: url(/src/graphics/png/footer-map-icon.png);                    object-fit: contain;\r\n                margin-right: 1rem;\r\n                vertical-align: middle;\r\n            }\r\n        }\r\n        & > img{\r\n            width: 65px;\r\n        }\r\n    }\r\n    &__addresses{\r\n        width:100%;\r\n        & > li{ \r\n            margin-top: 1.2rem;\r\n        }\r\n    }\r\n    .extra-details__container-wrapper{\r\n        display: flex;\r\n        flex-wrap: wrap;\r\n        gap: 1.2rem;\r\n        justify-content: flex-start;\r\n    }\r\n    .extra-details__map-link{\r\n        flex: 1 1 18rem;\r\n        min-width: 0;\r\n        font-size: 1.8rem;\r\n        padding: 1.6rem;\r\n        gap: 1.2rem;\r\n    }\r\n\r\n    &--shorted{\r\n        padding-block-start: 7rem;\r\n    }\r\n\r\n    @include m.tablet{\r\n        grid-template-columns: 1fr;\r\n        gap: 3rem;\r\n        padding-block: 8rem;\r\n        padding: 0;\r\n        // padding-inline: 2rem;\r\n        &__badge{\r\n            left: 50%;\r\n            translate: -50% 0;\r\n            width: 80%;\r\n        }\r\n        &__details{\r\n            max-width: none;\r\n            gap: 2.4rem;\r\n        }\r\n        &__title{\r\n            font-size: 4rem;\r\n            line-height: 1.1;\r\n        }\r\n        &__links{\r\n            // column-gap: 2rem;\r\n            row-gap: 1.2rem;\r\n            & > ul{\r\n                flex-basis: calc(50% - 1rem);\r\n            }\r\n        }\r\n    }\r\n\r\n    @include m.mobile{\r\n        flex-direction: column;\r\n        padding-block: 7rem;\r\n        gap: 2.4rem;\r\n        &__title{\r\n            font-size: 3.2rem;\r\n            line-height: 1.12;\r\n        }\r\n        &__subtitle{\r\n            font-size: 1.8rem;\r\n        }\r\n        &__text{\r\n            // font-size: 1.6rem;\r\n            line-height: 1.4;\r\n        }\r\n        &__links{\r\n            row-gap: 1rem;\r\n            & > ul{\r\n                flex-basis: 100%;\r\n            }\r\n        }\r\n        &__mails > li, &__phones > li, &__socials > li{\r\n            font-size: 1.5rem;\r\n        }\r\n        &__link > img{\r\n            width: 52px;\r\n        }\r\n        .extra-details__container-wrapper{\r\n            flex-direction: column;\r\n            width: 100%;\r\n            gap: 1rem;\r\n        }\r\n        .extra-details__map-link{\r\n            flex: 0 1 auto;\r\n            width: 100%;\r\n            font-size: 1.6rem;\r\n            padding: 1.4rem 1.2rem;\r\n            gap: 0.8rem;\r\n            min-height: 11.6rem;\r\n            justify-content: center;\r\n        }\r\n        .extra-details__map-image{\r\n            width: 52px;\r\n            height: 52px;\r\n        }\r\n        &__badge{\r\n            translate: 0 -150%;\r\n            text-align: center;\r\n        }\r\n        &__details{\r\n            width: 100%;\r\n        }\r\n    }\r\n}\r\n\r\n\r\n// Form\r\n.form {\r\n    display: flex;\r\n    flex-direction: column;\r\n    width: 60%;\r\n    min-width: 0;\r\n    padding: 4rem;\r\n    border: 1px solid vars.$borderColor;\r\n    border-radius: 2rem;\r\n    box-shadow: 0 8px 30px #05080d11 ;\r\n    background-color: #fff;\r\n    z-index: 10;\r\n\r\n    &--submitted {\r\n        min-height: 640px;\r\n        align-items: center;\r\n        justify-content: center;\r\n        text-align: center;\r\n\r\n        & > :not(.form__success) {\r\n            display: none !important;\r\n        }\r\n    }\r\n    &__success {\r\n        display: none;\r\n        width: 100%;\r\n        min-height: 520px;\r\n        margin: auto;\r\n        padding: 1rem 0;\r\n        flex-direction: column;\r\n        align-items: center;\r\n        justify-content: center;\r\n        text-align: center;\r\n        gap: 1.4rem;\r\n    }\r\n    &--submitted > .form__success {\r\n        display: flex;\r\n    }\r\n    &__success-icon {\r\n        width: 300px;\r\n        height: 300px;\r\n        object-fit: contain;\r\n    }\r\n    &__success-title {\r\n        color: vars.$darkColor;\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightSemibold;\r\n        font-size: 3rem;\r\n        line-height: 1.25;\r\n        max-width: 80%;\r\n    }\r\n    &__success-text {\r\n        color: vars.$greyColor;\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightMedium;\r\n        font-size: 1.8rem;\r\n        line-height: 1.45;\r\n        max-width: 80%;\r\n    }\r\n\r\n    &__title {\r\n        color: vars.$darkColor;\r\n        font-size: vars.$smallFontSize;\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightBold;\r\n        margin: 1rem 0;\r\n    }\r\n    &__text {\r\n        font-size: 1rem;\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightMedium;\r\n        color: vars.$greyColor;\r\n        text-align: center;\r\n        padding-top: 1rem;\r\n    }\r\n    &__status {\r\n        margin-top: 0.8rem;\r\n        min-height: 1.6rem;\r\n        font-size: 1.2rem;\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightMedium;\r\n        line-height: 1.35;\r\n        opacity: 0;\r\n        visibility: hidden;\r\n        transition: opacity vars.$fastAnimation ease;\r\n\r\n        &--visible {\r\n            opacity: 1;\r\n            visibility: visible;\r\n        }\r\n        &--info {\r\n            color: vars.$greyColor;\r\n        }\r\n        &--success {\r\n            color: #1f8d4d;\r\n        }\r\n        &--error {\r\n            color: #c23232;\r\n        }\r\n    }\r\n    &__radio {\r\n        margin-bottom: 1rem;\r\n        display: grid;\r\n        gap: 0.8rem;\r\n    }\r\n\r\n\r\n\r\n    & > input, & > select, & > textarea {\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightSemibold;\r\n        width: 100%;\r\n        &::placeholder{\r\n            font-family: vars.$mainFontRegular;\r\n        }\r\n    }\r\n    & > input {\r\n        padding: 1rem 1.6rem;\r\n        border: 1px solid vars.$borderColor;\r\n        border-radius: 1rem;\r\n        &:focus{\r\n            outline-color: vars.$secondaryColor;\r\n        }\r\n        &:not(:placeholder-shown) {\r\n            background-color: vars.$lightColor;\r\n            border-color: vars.$secondaryColor;\r\n        }\r\n    }\r\n    &__field--invalid {\r\n        border-color: #d84747 !important;\r\n        box-shadow: 0 0 0 1px #d8474740;\r\n    }\r\n    input[type=\"radio\"].form__field--invalid {\r\n        outline: 1px solid #d84747;\r\n        outline-offset: 1px;\r\n    }\r\n    & > label, &__radio > label {\r\n        border-color: vars.$borderColor;\r\n        margin-right: 0.5rem;\r\n        font-size: vars.$smallFontSize;\r\n        font-family: vars.$mainFontRegular;\r\n        line-height: 1.35;\r\n    }\r\n    &__radio > label{\r\n        display: flex;\r\n        align-items: flex-start;\r\n        gap: 0.7rem;\r\n        margin-right: 0;\r\n    }\r\n    &__radio > label > input{\r\n        flex: 0 0 auto;\r\n        margin-top: 0.2rem;\r\n    }\r\n    & > select {\r\n        padding: 1rem 1.6rem;\r\n        border-radius: 1rem;\r\n        border: 1px solid vars.$borderColor;\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightMedium;\r\n        background-color: #fff;\r\n    }\r\n    & > button {\r\n        padding: 1rem;\r\n        margin: 1rem 0;\r\n        border-radius: 1rem;\r\n        border: 1px solid vars.$primaryColor;\r\n        width: 100%;\r\n        text-align: center;\r\n    }\r\n\r\n    &__spacer{\r\n        height: 2rem;\r\n    }\r\n\r\n    textarea {\r\n        resize: none;\r\n        min-height: 18rem;\r\n        border-radius: 1rem;\r\n        border: 1px solid vars.$borderColor;\r\n        padding: 1rem;\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightMedium;\r\n        &:focus{\r\n            outline-color: vars.$secondaryColor;\r\n        }\r\n        &:not(:placeholder-shown) {\r\n            background-color: vars.$lightColor;\r\n            border-color: vars.$secondaryColor;\r\n        }\r\n    }\r\n\r\n    @include m.tablet{\r\n        padding: 2rem;\r\n    }\r\n    @include m.mobile{\r\n        margin: 0;\r\n        border-radius: 1.6rem;\r\n        &--submitted {\r\n            min-height: 560px;\r\n        }\r\n        &__success {\r\n            min-height: 460px;\r\n        }\r\n        &__success-icon {\r\n            width: 300px;\r\n            height: 300px;\r\n            max-width: 100%;\r\n        }\r\n        &__success-title {\r\n            font-size: 2.4rem;\r\n            max-width: 100%;\r\n        }\r\n        &__success-text {\r\n            font-size: 1.6rem;\r\n            max-width: 100%;\r\n        }\r\n        &__title{\r\n            line-height: 1.35;\r\n        }\r\n        &__spacer{\r\n            height: 1.4rem;\r\n        }\r\n        textarea{\r\n            min-height: 14rem;\r\n        }\r\n    }\r\n}\r\n\r\n// Header \r\n.header{\r\n    position: relative;\r\n    @extend .wrapper;\r\n    display: flex;\r\n    justify-content: space-between;\r\n    // outline: 1px solid bisque;\r\n    height: 12rem;\r\n    z-index: 1000;\r\n    &__logo{\r\n        display: flex;\r\n        flex-grow: 1;\r\n        & > img {\r\n            width: 180px;\r\n            margin: auto 0;\r\n            max-height: 100%;\r\n        }\r\n    }   \r\n    &__nav-list{\r\n        height: 100%;\r\n        display: flex;\r\n        align-content: center;\r\n        &-services{\r\n            display: none;\r\n            position: absolute;\r\n            right: 0;\r\n            transform: translateY(5%);\r\n            padding: 1rem 1.5rem;\r\n            \r\n            background-color: #ffffff7e;\r\n            backdrop-filter: blur(8px);\r\n            border-radius: 1rem;\r\n            border: 1px solid vars.$borderColor;\r\n            & > li{\r\n                padding: 0.3rem 0;\r\n                text-align: right;\r\n                width: 300px;\r\n                & > a{\r\n                    transition: 0.33s;\r\n                    padding: 0.3rem 0;\r\n                    color: vars.$darkColor;\r\n                    font-family: vars.$mainFontFamily;\r\n                    font-weight: vars.$mainFontWeightMedium;\r\n                    white-space: nowrap;\r\n                    &:hover{\r\n                        color: vars.$primaryColor;\r\n                        font-family: vars.$mainFontFamily;\r\n                        font-weight: vars.$mainFontWeightSemibold;\r\n                    }\r\n                }\r\n\r\n            }\r\n        }\r\n    }\r\n    &__nav-item{\r\n        margin: auto 0.5rem;\r\n        position: relative;\r\n        &-services{\r\n            &:hover{\r\n                & > .header__nav-list-services{\r\n                    display: block;\r\n                }\r\n            }\r\n        }\r\n    }\r\n    &__nav-link{\r\n        padding: 1.8rem 0.5rem;\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightMedium;\r\n        color: vars.$darkColor;\r\n    }\r\n    &__lang{\r\n        background: none;\r\n        border: none;\r\n        margin: auto 0 auto 3rem;\r\n        // outline: 1px solid red;\r\n        & > img{\r\n            padding: 2rem 1rem;\r\n            padding-left: 2rem;\r\n        }\r\n        &:hover{\r\n            & > .header__lang-switcher{\r\n                display: flex;\r\n            }\r\n        }\r\n    }\r\n    &__lang-switcher{\r\n        position: absolute;\r\n        display: none;\r\n        right: 0;\r\n        bottom: -60%;\r\n        flex-direction: column;\r\n        justify-content: center;\r\n        background-color: #fff;\r\n        border: 1px solid vars.$borderColor;\r\n        padding: 0.5rem;\r\n        border-radius: 1rem;\r\n        &-item{\r\n            margin: 0.1rem 0;\r\n            transition: 0.13s;\r\n            display: flex;\r\n            align-items: center;\r\n            padding: 1rem;\r\n            background-color: vars.$lightColor;\r\n            border: none;\r\n            border-radius: 1rem;\r\n            & > img {\r\n                margin-right: 1rem;\r\n                filter: drop-shadow(0 0 4px #36363671);\r\n            }\r\n            & > p{\r\n                font-size: vars.$smallFontSize;\r\n                font-family: vars.$mainFontFamily;\r\n                font-weight: vars.$mainFontWeightSemibold;\r\n            }\r\n            &--selected{\r\n                color: vars.$primaryColor;\r\n            }\r\n        }\r\n    }\r\n\r\n    &__burger{\r\n        display: none;\r\n        align-items: center;\r\n        justify-content: center;\r\n        flex-direction: column;\r\n        width: 44px;\r\n        height: 44px;\r\n        padding: 0;\r\n        margin: auto 0;\r\n        border: 1px solid vars.$borderColor;\r\n        border-radius: 1.2rem;\r\n        background-color: #fff;\r\n        cursor: pointer;\r\n    }\r\n    &__burger-line{\r\n        display: block;\r\n        width: 20px;\r\n        height: 2px;\r\n        background-color: vars.$darkColor;\r\n        border-radius: 2px;\r\n        transition: transform vars.$normalAnimation ease, opacity vars.$normalAnimation ease;\r\n        & + &{\r\n            margin-top: 5px;\r\n        }\r\n    }\r\n    &__menu{\r\n        display: flex;\r\n        align-items: center;\r\n    }\r\n    &__menu-panel{\r\n        display: flex;\r\n        align-items: center;\r\n    }\r\n    &__menu-close{\r\n        display: none;\r\n    }\r\n    &__menu-close-line{\r\n        display: block;\r\n    }\r\n    &__menu-overlay{\r\n        display: none;\r\n    }\r\n\r\n    &--menu-open{\r\n        .header__burger-line{\r\n            &:nth-child(1){\r\n                transform: translateY(7px) rotate(45deg);\r\n            }\r\n            &:nth-child(2){\r\n                opacity: 0;\r\n            }\r\n            &:nth-child(3){\r\n                transform: translateY(-7px) rotate(-45deg);\r\n            }\r\n        }\r\n        .header__menu{\r\n            pointer-events: auto;\r\n        }\r\n        .header__menu-panel{\r\n            transform: translateX(0);\r\n        }\r\n        .header__menu-overlay{\r\n            opacity: 1;\r\n            pointer-events: auto;\r\n        }\r\n    }\r\n\r\n    @include m.tablet{\r\n        &__burger{\r\n            display: inline-flex;\r\n            margin-left: auto;\r\n        }\r\n        &__nav,\r\n        &__lang{\r\n            display: none;\r\n        }\r\n        &__menu{\r\n            position: fixed;\r\n            inset: 0;\r\n            pointer-events: none;\r\n            z-index: 1002;\r\n        }\r\n        &__menu-panel{\r\n            position: fixed;\r\n            top: 0;\r\n            right: 0;\r\n            height: 100vh;\r\n            width: min(85vw, 360px);\r\n            padding: 10rem 2.4rem 2.4rem;\r\n            background-color: #fff;\r\n            box-shadow: -20px 0 40px rgba(30, 39, 54, 0.15);\r\n            transform: translateX(100%);\r\n            transition: transform vars.$slowAnimation ease;\r\n            flex-direction: column;\r\n            align-items: flex-start;\r\n            gap: 2.4rem;\r\n            overflow-y: auto;\r\n            z-index: 1003;\r\n        }\r\n        &__menu-close{\r\n            display: inline-flex;\r\n            position: absolute;\r\n            top: 2.4rem;\r\n            right: 2.4rem;\r\n            align-items: center;\r\n            justify-content: center;\r\n            width: 44px;\r\n            height: 44px;\r\n            padding: 0;\r\n            border: 1px solid vars.$borderColor;\r\n            border-radius: 1.2rem;\r\n            background-color: #fff;\r\n            cursor: pointer;\r\n            z-index: 1;\r\n        }\r\n        &__menu-close-line{\r\n            position: absolute;\r\n            width: 20px;\r\n            height: 2px;\r\n            background-color: vars.$darkColor;\r\n            border-radius: 2px;\r\n            &:first-child{\r\n                transform: rotate(45deg);\r\n            }\r\n            &:last-child{\r\n                transform: rotate(-45deg);\r\n            }\r\n        }\r\n        &__menu-overlay{\r\n            display: block;\r\n            position: fixed;\r\n            inset: 0;\r\n            background-color: rgba(30, 39, 54, 0.45);\r\n            opacity: 0;\r\n            pointer-events: none;\r\n            transition: opacity vars.$slowAnimation ease;\r\n            z-index: 1001;\r\n        }\r\n        &__menu .header__nav,\r\n        &__menu .header__lang{\r\n            display: block;\r\n            width: 100%;\r\n        }\r\n        &__menu .header__nav-list{\r\n            height: auto;\r\n            flex-direction: column;\r\n            align-items: flex-start;\r\n            gap: 0.4rem;\r\n        }\r\n        &__menu .header__nav-item{\r\n            margin: 0;\r\n            width: 100%;\r\n        }\r\n        &__menu .header__nav-link{\r\n            display: flex;\r\n            align-items: center;\r\n            width: 100%;\r\n            min-height: 4.8rem;\r\n            padding: 1rem 1.2rem;\r\n            border-radius: 1.2rem;\r\n            line-height: 1.35;\r\n        }\r\n        &__menu .header__nav-item-services > .header__nav-link{\r\n            justify-content: space-between;\r\n            gap: 1.2rem;\r\n            &::after{\r\n                content: '';\r\n                flex-shrink: 0;\r\n                width: 1rem;\r\n                height: 1rem;\r\n                margin-left: auto;\r\n                border-right: 2px solid currentColor;\r\n                border-bottom: 2px solid currentColor;\r\n                transform: rotate(45deg) translateY(-0.2rem);\r\n                transition: transform vars.$normalAnimation ease;\r\n            }\r\n        }\r\n        &__menu .header__nav-list-services{\r\n            display: block;\r\n            position: static;\r\n            right: auto;\r\n            transform: none;\r\n            padding: 0 0 0 0.6rem;\r\n            background-color: transparent;\r\n            border: none;\r\n            max-height: 0;\r\n            margin-top: 0;\r\n            opacity: 0;\r\n            overflow: hidden;\r\n            pointer-events: none;\r\n            transition: max-height vars.$slowAnimation ease, opacity vars.$normalAnimation ease, margin-top vars.$normalAnimation ease;\r\n        }\r\n        &__menu .header__nav-list-services > li + li{\r\n            margin-top: 0.4rem;\r\n        }\r\n        &__menu .header__nav-list-services > li{\r\n            text-align: left;\r\n            width: 100%;\r\n        }\r\n        &__menu .header__nav-list-services > li > a{\r\n            display: flex;\r\n            align-items: center;\r\n            width: 100%;\r\n            min-height: 4.8rem;\r\n            padding: 1rem 1.2rem;\r\n            white-space: normal;\r\n            line-height: 1.35;\r\n            border-radius: 1.2rem;\r\n            background-color: rgba(26, 110, 255, 0.08);\r\n        }\r\n        &__menu .header__nav-item-services--expanded > .header__nav-link{\r\n            margin-bottom: 0.2rem;\r\n            &::after{\r\n                transform: rotate(-135deg) translateY(0.2rem);\r\n            }\r\n        }\r\n        &__menu .header__nav-item-services--expanded > .header__nav-list-services{\r\n            max-height: 80rem;\r\n            margin-top: 0.2rem;\r\n            opacity: 1;\r\n            pointer-events: auto;\r\n        }\r\n        &__menu .header__lang{\r\n            margin: 1.2rem 0 0;\r\n        }\r\n        &__menu .header__lang > img{\r\n            display: none;\r\n        }\r\n        &__menu .header__lang-switcher{\r\n            position: static;\r\n            display: flex;\r\n            flex-direction: row;\r\n            gap: 0.6rem;\r\n            padding: 0;\r\n            background-color: transparent;\r\n            border: none;\r\n        }\r\n        &__menu .header__lang-switcher-item{\r\n            margin: 0;\r\n        }\r\n    }\r\n    \r\n}\r\n// Footer\r\n.footer {\r\n    display: flex;\r\n    flex-direction: column;\r\n    justify-content: center;\r\n    color: #fff;\r\n    min-height: 40rem;\r\n    padding: 5rem 2rem;\r\n    background-color: vars.$darkColor;\r\n    \r\n    &__grid{\r\n        max-width: 1280px;\r\n        margin: 0 auto;\r\n        display: grid;\r\n        grid-template-columns: 1.5fr 1fr 1.2fr;\r\n        column-gap: 3rem;\r\n        row-gap: 3rem;\r\n    }\r\n    &__logo{\r\n        margin: auto 2rem 5rem 0;\r\n        &-caption{\r\n            margin-bottom: 1rem;\r\n            font-size: vars.$smallFontSize;\r\n            color: vars.$lightGreyColor;\r\n        }\r\n    }\r\n    &__title{\r\n        font-style: normal;\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightSemibold;\r\n        font-size: vars.$h5Size;\r\n        margin-bottom: 1rem;\r\n    }\r\n    &__brand{\r\n        max-width: 50rem;\r\n        align-content: end;\r\n    }\r\n    &__list{\r\n        &-item{\r\n            &::before{\r\n                content: \"•\";\r\n                font-size: 2.3rem;\r\n                color:vars.$primaryColor;\r\n                vertical-align: middle;\r\n                margin-right: 0.5rem;\r\n            }\r\n            &--address{\r\n                display: flex;\r\n                align-items: center;\r\n                &::before{\r\n                    display: block;\r\n                    width: 20px;\r\n                    content: url(/src/graphics/svg/map-icon.svg);                    object-fit: contain;\r\n                }\r\n            }\r\n            &--mail{\r\n                display: flex;\r\n                align-items: center;\r\n                &::before{\r\n                    display: block;\r\n                    width: 20px;\r\n                    content: url(/src/graphics/svg/mail-icon.svg);\r\n                }\r\n            }\r\n            &--phone{\r\n                display: flex;\r\n                align-items: center;\r\n                &::before{\r\n                    display: block;\r\n                    width: 20px;\r\n                    content: url(/src/graphics/svg/phone-icon.svg);\r\n                }\r\n            }\r\n        }\r\n        &-link{\r\n            font-size: vars.$smallFontSize;\r\n            vertical-align: middle;\r\n            color: #fff;\r\n        }\r\n        &--contacts{\r\n            & > li{\r\n                &:nth-child(2n){\r\n                    margin-bottom: 1rem;\r\n                }\r\n            }\r\n        }\r\n    }\r\n    &__divider{\r\n        background-color: vars.$greyColor;\r\n        height: 1px;\r\n        width: 100%;\r\n        margin: 2rem auto;\r\n    }\r\n    &__afterline{\r\n        display: flex;\r\n        justify-content: space-between;\r\n        align-items: center;\r\n        flex-wrap: wrap;\r\n        gap: 1rem;\r\n        max-width: 1280px;\r\n        width: 100%;\r\n        margin: 0 auto;\r\n        // position: relative;\r\n    }\r\n    &__copyright{\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightMedium;\r\n        color: #fff;\r\n        text-align: left;\r\n    }\r\n    &__policy{\r\n        // right: 0;\r\n        text-decoration: underline;\r\n        color:#fff;\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightMedium;\r\n    }\r\n    &__messengers{\r\n        display: flex;\r\n        gap: 0.2rem;\r\n        flex-wrap: wrap;\r\n        & > a {\r\n            & > img{\r\n                width: 50px;;\r\n            }\r\n        }\r\n    }\r\n}\r\n\r\n@media (max-width: vars.$tablet) {\r\n    .footer {\r\n        padding: 4rem 3rem;\r\n    }\r\n\r\n    .footer__grid {\r\n        grid-template-columns: 1fr 1fr;\r\n        column-gap: 2rem;\r\n    }\r\n\r\n    .footer__brand {\r\n        grid-column: 1 / -1;\r\n        max-width: none;\r\n    }\r\n}\r\n\r\n@media (max-width: vars.$mobile) {\r\n    .footer {\r\n        padding: 3rem 2rem;\r\n    }\r\n\r\n    .footer__grid {\r\n        grid-template-columns: 1fr;\r\n        row-gap: 2.4rem;\r\n    }\r\n\r\n    .footer__logo {\r\n        margin: 0 0 2rem 0;\r\n    }\r\n\r\n    .footer__afterline {\r\n        flex-direction: column;\r\n        align-items: flex-start;\r\n    }\r\n\r\n    .footer__messengers > a > img {\r\n        width: 40px;\r\n    }\r\n\r\n    .footer__list-item--address,\r\n    .footer__list-item--mail,\r\n    .footer__list-item--phone {\r\n        align-items: flex-start;\r\n    }\r\n}\r\n\r\n.hero {\r\n    display: flex;\r\n    align-items: center;\r\n    flex-direction: column;\r\n    gap: 4rem;\r\n    padding-block: 20rem;\r\n\r\n    &__title, &__subtitle {text-align: center}\r\n    &__subtitle{\r\n        line-height: 1.3;\r\n        color: vars.$greyColor;\r\n    }\r\n\r\n    &__image{\r\n        position: relative;\r\n        margin: auto;\r\n        width: 500px;\r\n        max-width: 100%;\r\n        height: 400px;\r\n        z-index: -1;\r\n        & > img{\r\n            // outline: 1px solid red;\r\n            position: absolute;\r\n            top: 0;\r\n            width: 100%;\r\n            height: 100%;\r\n        }\r\n\r\n        &--registration,\r\n        &--logistics{\r\n            aspect-ratio: 380.4 / 288.4;\r\n            height: auto;\r\n        }\r\n    }\r\n\r\n    &--service{\r\n        padding-block: 10rem;\r\n        display: grid;\r\n        grid-template-columns: minmax(0, 50%) minmax(0, 1fr);\r\n        grid-template-rows: auto auto;\r\n        grid-template-areas:\r\n            \"title image\"\r\n            \"details image\";\r\n        column-gap: 4rem;\r\n        row-gap: 2rem;\r\n        align-items: stretch;\r\n\r\n        & > .hero__title{\r\n            grid-area: title;\r\n            margin: 0;\r\n            align-self: end;\r\n            text-align: left;\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightSemibold;\r\n            color: vars.$darkColor;\r\n        }\r\n\r\n        & > .hero__details{\r\n            grid-area: details;\r\n            display: flex;\r\n            flex-direction: column;\r\n            gap: 2.4rem;\r\n            text-align: left;\r\n            width: 100%;\r\n            max-width: 100%;\r\n\r\n            & > p {\r\n                text-align: left;\r\n            }\r\n            \r\n            & > .hero__subtitle {\r\n                font-family: vars.$mainFontFamily;\r\n                font-weight: vars.$mainFontWeightMedium;\r\n                color: vars.$darkColor;\r\n            }\r\n\r\n            & > .btn {\r\n                align-self: flex-start;\r\n                margin-inline: 0;\r\n            }\r\n        }\r\n\r\n        & > .hero__image{\r\n            grid-area: image;\r\n            width: min(100%, 52rem);\r\n            justify-self: center;\r\n            align-self: center;\r\n            margin: 0;\r\n        }\r\n    }\r\n    &--aboutus{\r\n        background: linear-gradient(\r\n            0deg,\r\n            #DFEDFF,\r\n            #ffffff\r\n        ); \r\n        padding-block-end: 5rem;\r\n        & > .service-card{\r\n            width: 80%;\r\n            padding: 5rem;\r\n        }\r\n        & > h4{\r\n            z-index: 1;\r\n        }\r\n        & > h1{\r\n            z-index: 1;\r\n        }\r\n        @include m.mobile{ \r\n            & > .hero{\r\n                &__title{\r\n                    width: 90%;\r\n                    font-size: vars.$h3Size;\r\n                }\r\n                &__subtitle{\r\n                    width: 90%;\r\n                    font-size: vars.$pSize;\r\n                }\r\n            }\r\n            & > .service-card--base{\r\n                padding: 2rem;\r\n                width: 90%;\r\n                text-align: justify;\r\n            }\r\n        }\r\n    }\r\n\r\n    @media (min-width: 1024px) and (max-width: 1689px){\r\n        &:not(.hero--service):not(.hero--aboutus){\r\n            padding-block: 15rem;\r\n        }\r\n    }\r\n\r\n    @include m.tablet{\r\n        padding-block: 8rem;\r\n        \r\n        &__title{\r\n            font-size: vars.$h1Size * 0.7;\r\n            line-height: 1;\r\n            // font-size: vars.$h2Size;\r\n            // font-family: vars.$mainFontMedium;\r\n        }\r\n\r\n        &--service{\r\n            padding-block: 6rem;\r\n            grid-template-columns: 1fr;\r\n            grid-template-areas:\r\n                \"title\"\r\n                \"image\"\r\n                \"details\";\r\n            gap: 2rem;\r\n\r\n            & > .hero__title{\r\n                text-align: center;\r\n            }\r\n\r\n            & > .hero__details{\r\n                width: 100%;\r\n                max-width: 100%;\r\n                gap: 2.2rem;\r\n                align-items: center;\r\n                text-align: center;\r\n\r\n                & > p {\r\n                    text-align: center;\r\n                }\r\n\r\n                & > .btn{\r\n                    align-self: center;\r\n                    margin-inline: 0;\r\n                }\r\n            }\r\n\r\n            & > .hero__image{\r\n                justify-self: center;\r\n                width: min(100%, 42rem);\r\n                height: clamp(20rem, 62vw, 30rem);\r\n            }\r\n\r\n            & > .hero__image--registration,\r\n            & > .hero__image--logistics{\r\n                height: auto;\r\n            }\r\n        }\r\n    }\r\n\r\n    @include m.mobile{\r\n        &__cta{\r\n            & > .btn{\r\n                width: 100%;\r\n            }\r\n        }\r\n\r\n        &--service{\r\n            padding-block: 4rem;\r\n            gap: 2.4rem;\r\n\r\n            & > .hero{\r\n                &__details{\r\n                    gap: 2rem;\r\n                    padding-block-end: 0;\r\n                }\r\n                &__title{\r\n                    font-size: vars.$h3Size;\r\n                }\r\n                &__subtitle{\r\n                    line-height: 1.45;\r\n                }\r\n\r\n                & > .btn{\r\n                    width: 100%;\r\n                }\r\n            }\r\n\r\n            & > .hero__image{\r\n                width: 100%;\r\n            }\r\n        }\r\n        &--aboutus{\r\n            & > .hero{\r\n                &__title{\r\n                    font-size: vars.$h3Size;\r\n                }\r\n                &__subtitle{\r\n                    font-size: vars.$pSize;\r\n                    // line-height: 1.1;\r\n                }\r\n            }\r\n            & > .service-card--base{\r\n                padding: 2rem;\r\n                width: 100%;\r\n            }\r\n        }\r\n    }\r\n\r\n}\r\n\r\n// RESIDENCE PERMIT PAGE //\r\n\r\n.residence-permit__UNQ{\r\n    padding: 3rem 0;\r\n    @include m.mobile{\r\n        padding-top: 0;\r\n        font-size: vars.$h5Size;\r\n    }\r\n}\r\n\r\n.hero__title--residence{\r\n    font-family: vars.$mainFontFamily;\r\n    font-weight: vars.$mainFontWeightSemibold;\r\n}\r\n\r\n.methods{\r\n    display: flex;\r\n    flex-direction: column;\r\n    gap: 2rem;\r\n    padding-block: 2rem 6rem;\r\n\r\n    @include m.tablet{\r\n        gap: 1.6rem;\r\n        padding-block: 1rem 4rem;\r\n    }\r\n\r\n    @include m.mobile{\r\n        gap: 1.2rem;\r\n        padding-block: 0 3rem;\r\n    }\r\n}\r\n\r\n.method-title{\r\n    padding: 2rem;\r\n    background-color: vars.$lightColor;\r\n    border-radius: 1.5rem;\r\n    border: 1px solid vars.$borderColor;\r\n    text-align: center;\r\n}\r\n.method-spacing{\r\n    padding-block: 3rem;\r\n}\r\n\r\n.business-method{\r\n    @extend .method-spacing;\r\n    &__title{\r\n        @extend .method-title;\r\n    }\r\n    &__benefits{\r\n        padding-block: 3rem;\r\n        display: flex;\r\n        justify-content: center;\r\n        align-items: flex-start;\r\n        gap: 3rem;\r\n        &-header{\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightSemibold;\r\n            text-align: end;\r\n            margin-bottom: 2rem;\r\n        }\r\n    }\r\n    &__details{\r\n        height: 100%;\r\n        width: min(100%, 560px);\r\n        min-width: 0;\r\n        display: flex;\r\n        flex-direction: column;\r\n        justify-content: center;\r\n        & > h5 {\r\n            margin-bottom: 2.6rem;\r\n            font-size: vars.$pSize;\r\n        }\r\n        & > p {\r\n            margin-bottom: 2.5rem;\r\n        }\r\n\r\n    }\r\n    &__price{ \r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightBold;\r\n    }\r\n\r\n    @include m.tablet{\r\n        padding-block: 2rem;\r\n\r\n        &__benefits{\r\n            padding-block: 2rem;\r\n            flex-direction: column;\r\n            gap: 2rem;\r\n        }\r\n\r\n        &__benefits-header{\r\n            text-align: start;\r\n            margin-bottom: 1.4rem;\r\n        }\r\n\r\n        &__details{\r\n            width: 100%;\r\n            max-width: 100%;\r\n        }\r\n\r\n        .service-card__benefits--residence{\r\n            width: 100%;\r\n            margin-right: 0;\r\n            padding-block: 0;\r\n\r\n            & > li{\r\n                margin: 0.5rem 0 0.5rem 2.6rem;\r\n                text-align: start;\r\n\r\n                &::before{\r\n                    content: url(/src/graphics/svg/benefit-icon.svg);\r\n                }\r\n\r\n                &::after{\r\n                    content: none;\r\n                }\r\n            }\r\n        }\r\n    }\r\n\r\n    @include m.mobile{\r\n        &__benefits{\r\n            gap: 1.6rem;\r\n        }\r\n\r\n        &__details{\r\n            & > h5{\r\n                margin-bottom: 1.6rem;\r\n                line-height: 1.4;\r\n            }\r\n            & > p{\r\n                margin-bottom: 1.6rem;\r\n                line-height: 1.45;\r\n            }\r\n        }\r\n    }\r\n}\r\n.work-method{\r\n    &__title{\r\n        @extend .method-title;\r\n    }\r\n    &__benefits{\r\n        @extend .business-method__benefits;\r\n        justify-content: end;\r\n    }\r\n    &__details{\r\n        display: flex;\r\n        justify-content: center;\r\n        align-items: flex-start;\r\n        padding-block: 3rem;\r\n        gap: 2rem;\r\n    }\r\n    &__spacer{\r\n        margin: 3rem;\r\n        width: 50%;\r\n        & > p {\r\n            margin-bottom: 2rem;\r\n        }\r\n        &--right{\r\n            max-width: 560px;\r\n            margin: 0;\r\n        }\r\n        & > h5 {\r\n            text-align: end;\r\n        }\r\n    }\r\n    &__price{ \r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightBold;\r\n    }\r\n\r\n    @include m.tablet{\r\n        &__details{\r\n            flex-direction: column;\r\n            gap: 2rem;\r\n            align-items: stretch;\r\n        }\r\n\r\n        &__spacer{\r\n            width: 100%;\r\n            margin: 0;\r\n\r\n            & > h5{\r\n                text-align: start;\r\n            }\r\n\r\n            &--right{\r\n                max-width: 100%;\r\n                margin-right: 0;\r\n            }\r\n        }\r\n    }\r\n\r\n    @include m.mobile{\r\n        &__details{\r\n            gap: 1.6rem;\r\n        }\r\n\r\n        &__spacer{\r\n            & > p{\r\n                margin-bottom: 1.6rem;\r\n                line-height: 1.45;\r\n            }\r\n            & > h5{\r\n                line-height: 1.4;\r\n            }\r\n        }\r\n\r\n        &__title{\r\n            margin-bottom: 2rem;\r\n        }\r\n    }\r\n}\r\n\r\n.accordion-container{\r\n    padding-block: 5rem;\r\n    &--bdf-blur{\r\n        & > .ac{\r\n            backdrop-filter: blur(12px);\r\n        }\r\n    }\r\n}\r\n.ac{\r\n    margin: 1rem 0;\r\n    padding: 2rem;\r\n    border-radius: 2rem;\r\n    background-color: #ffffffbd;\r\n    border-color: vars.$borderColor;\r\n    &-divider{\r\n        height: 1px;\r\n        background-color: vars.$borderColor;\r\n        margin: 1rem 0;\r\n    }\r\n    &-trigger:active{\r\n        color: vars.$primaryColor;\r\n    }\r\n    &-panel{\r\n        & > p{\r\n            color: vars.$greyColor;\r\n            line-height: 1.2;\r\n        }\r\n    }\r\n}\r\n.ac.is-active > .ac-header .ac-trigger {\r\n    color: vars.$primaryColor;           \r\n}\r\n\r\n.faq{\r\n    padding-block: 7rem    ;\r\n    &-header{\r\n    font-family: vars.$mainFontRegular;\r\n    font-size: 2rem;}\r\n    &__title{\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightSemibold;\r\n    }\r\n    @include m.mobile{\r\n        padding-block: 3rem;\r\n        & > .accordion-container{\r\n            padding-block: 2rem;\r\n        }\r\n    }\r\n}\r\n\r\n// SOCIAL CARD\r\n.sc-details{\r\n    position: relative;\r\n    padding-block: 7rem;\r\n    overflow: hidden;\r\n\r\n    &__grid{\r\n        position: relative;\r\n        z-index: 1;\r\n        display: grid;\r\n        grid-template-columns: repeat(2, minmax(0, 1fr));\r\n        gap: 3rem;\r\n    }\r\n    &__card{\r\n        position: relative;\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 2rem;\r\n        padding: 3rem;\r\n        border-radius: 2.4rem;\r\n        border: 1px solid vars.$borderColor;\r\n        background-color: #fff;\r\n        overflow: hidden;\r\n\r\n        & > *{\r\n            position: relative;\r\n            z-index: 1;\r\n        }\r\n    }\r\n    &__card-header{\r\n        display: flex;\r\n        align-items: center;\r\n        gap: 1.6rem;\r\n    }\r\n    &__card-index{\r\n        width: 44px;\r\n        height: 44px;\r\n        border-radius: 100%;\r\n        display: inline-flex;\r\n        align-items: center;\r\n        justify-content: center;\r\n        background-color: vars.$primaryColor;\r\n        color: #fff;\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightBold;\r\n        font-size: 1.5rem;\r\n        letter-spacing: 0.02em;\r\n    }\r\n    &__title{\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightSemibold;\r\n        color: vars.$darkColor;\r\n    }\r\n    &__text{\r\n        color: vars.$greyColor;\r\n        line-height: 1.45;\r\n    }\r\n    &__text-group{\r\n        display: grid;\r\n        gap: 1.4rem;\r\n    }\r\n\r\n    @include m.tablet{\r\n        &__grid{\r\n            grid-template-columns: 1fr;\r\n        }\r\n    }\r\n    @include m.mobile{\r\n        padding-block: 5rem;\r\n        &__card{\r\n            padding: 2.4rem;\r\n        }\r\n        &__card-header{\r\n            align-items: flex-start;\r\n            gap: 1.2rem;\r\n        }\r\n        &__card-index{\r\n            display: none;\r\n        }\r\n    }\r\n}\r\n\r\n\r\n// LOGISTICS & CUSTOMS\r\n.workstyle{\r\n    padding-block: 4rem;\r\n    &__title{\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightSemibold;\r\n        text-align: center;\r\n        margin-bottom: 1rem;\r\n    }\r\n    &__lead{\r\n        text-align: center;\r\n        margin-bottom: 9rem;\r\n    }\r\n    &__approaches{\r\n        display: flex;\r\n        justify-content: space-between;\r\n        align-items: start;\r\n    }\r\n\r\n    @include m.tablet{\r\n        padding-block: 3rem;\r\n\r\n        &__lead{\r\n            margin-bottom: 4rem;\r\n        }\r\n\r\n        &__approaches{\r\n            flex-direction: column;\r\n            gap: 2.4rem;\r\n        }\r\n\r\n        &__approaches > .scheme-container{\r\n            width: 100%;\r\n            max-width: 100%;\r\n        }\r\n    }\r\n\r\n    @include m.mobile{\r\n        padding-block: 2rem;\r\n\r\n        &__lead{\r\n            margin-bottom: 2.6rem;\r\n            font-size: vars.$pSize;\r\n        }\r\n\r\n        &__approaches{\r\n            gap: 1.8rem;\r\n        }\r\n    }\r\n}\r\n\r\n// IE & LLC \r\n.ie-details{\r\n    display: flex;\r\n    justify-content: space-between;\r\n    &__cards{\r\n        // outline: 1px solid green;\r\n        width: 50%;\r\n    }\r\n    &__description{\r\n        padding: 2.5rem 2rem;\r\n        max-width: 50%;\r\n        // outline: 1px dashed pink;\r\n        &-title{\r\n            // outline: 1px dashed peachpuff; \r\n            margin-bottom: 3rem;\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightMedium;\r\n        }\r\n    }\r\n\r\n    &__benefits{\r\n        & > li {\r\n            & > h4{ \r\n                font-family: vars.$mainFontFamily;\r\n                font-weight: vars.$mainFontWeightMedium;\r\n                margin-bottom: 0.5rem;\r\n            }\r\n            & > p{\r\n                margin-bottom: 2rem;\r\n                color: vars.$greyColor;\r\n            }\r\n        }\r\n    }\r\n    @include m.mobile{\r\n        flex-direction: column;\r\n        &__cards{\r\n            width: 100%;\r\n            & > .service-card{\r\n                margin: 2rem 0;\r\n            }\r\n        }\r\n        &__description{\r\n            max-width: 100%;\r\n            padding: 0;\r\n        }\r\n    }\r\n}\r\n.ie-scheme{\r\n    padding-block: 7rem;\r\n    & > .scheme-container__title{\r\n        text-align: center;\r\n    }\r\n    @media (min-width: 768px){\r\n        .scheme--horizontal{\r\n            --ie-scheme-gap: 2rem;\r\n            --ie-scheme-step-marker-offset: 8rem;\r\n            --ie-scheme-step-marker-size: 5.4rem;\r\n            --ie-scheme-line-thickness: 0.3rem;\r\n            display: grid;\r\n            grid-template-columns: repeat(4, minmax(0, 1fr));\r\n            align-items: start;\r\n            gap: var(--ie-scheme-gap);\r\n\r\n            & > .scheme__item{\r\n                min-width: 0;\r\n                margin: 0;\r\n                height: 100%;\r\n            }\r\n\r\n            & > .scheme__item > .scheme__item-title{\r\n                overflow-wrap: anywhere;\r\n            }\r\n\r\n            & > .scheme__line{\r\n                top: calc(\r\n                    (-1 * var(--ie-scheme-step-marker-offset)) +\r\n                    (var(--ie-scheme-step-marker-size) / 2) -\r\n                    (var(--ie-scheme-line-thickness) / 2)\r\n                );\r\n                left: calc(12.5% - (var(--ie-scheme-gap) * 0.375));\r\n                right: calc(12.5% - (var(--ie-scheme-gap) * 0.375));\r\n                width: auto;\r\n                height: var(--ie-scheme-line-thickness);\r\n            }\r\n\r\n            & > .scheme__line--position1{\r\n                translate: 0 10px;\r\n            }\r\n        }\r\n    }\r\n    @include m.mobile{\r\n        padding-block: 2rem;\r\n    }\r\n}\r\n\r\n.llc-details{\r\n    display: grid;\r\n    gap: 3.2rem;\r\n    padding-block: 2rem 5rem;\r\n\r\n    &__cards{\r\n        display: grid;\r\n        grid-template-columns: repeat(2, minmax(0, 1fr));\r\n        gap: 2rem;\r\n        & > .service-card--glow{\r\n            width: 100%;\r\n            height: 100%;\r\n            margin: 0;\r\n        }\r\n    }\r\n\r\n    &__description{\r\n        display: grid;\r\n        grid-template-columns: repeat(2, minmax(0, 1fr));\r\n        gap: 2rem;\r\n        align-items: start;\r\n        padding: 0;\r\n\r\n        &-text{\r\n            width: 100%;\r\n            text-align: end;\r\n            line-height: 1.45;\r\n            color: vars.$greyColor;\r\n            padding: 1.2rem 2rem 0 0;\r\n        }\r\n\r\n        &-wrapper{\r\n            width: 100%;\r\n            padding: 0 0 0 2rem;\r\n        }\r\n\r\n        &-title{\r\n            margin-bottom: 1.8rem;\r\n        }\r\n    }\r\n\r\n    @include m.tablet{\r\n        gap: 2.6rem;\r\n\r\n        &__cards{\r\n            grid-template-columns: 1fr;\r\n        }\r\n\r\n        &__description{\r\n            grid-template-columns: 1fr;\r\n            gap: 1.8rem;\r\n\r\n            &-text{\r\n                text-align: start;\r\n                padding: 0;\r\n            }\r\n\r\n            &-wrapper{\r\n                padding: 0;\r\n            }\r\n        }\r\n    }\r\n\r\n    @include m.mobile{\r\n        gap: 2rem;\r\n        padding-block: 1rem 3rem;\r\n\r\n        &__cards{\r\n            gap: 1.4rem;\r\n        }\r\n\r\n        &__description{\r\n            gap: 1.4rem;\r\n\r\n            &-text{\r\n                margin: 2rem 0;\r\n                line-height: 1.4;\r\n                text-align: justify;\r\n            }\r\n\r\n            &-title{\r\n                margin-bottom: 1.2rem;\r\n            }\r\n        }\r\n    }\r\n}\r\n.llc-scheme{\r\n    padding-block-end: 7rem;\r\n    width: 100%;\r\n    @include m.mobile{\r\n        padding-block: 2rem;\r\n    }\r\n}\r\n\r\n//CITIZENSHIP\r\n\r\n.citizenship-approaches{\r\n    // outline: 1px solid red;\r\n    padding-block-end: 8rem;\r\n    display: flex;\r\n    align-items: stretch;\r\n    gap: 2rem;\r\n\r\n    &__cards{\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 2rem;\r\n        max-width: 50%;\r\n        min-width: 0;\r\n        flex: 1 1 0;\r\n        & > .service-card{\r\n            margin: 0;\r\n            height: auto;\r\n        }\r\n        &--fullheight{\r\n            & > .service-card{\r\n                justify-content: space-around;\r\n                height: 100%;\r\n            }\r\n        }\r\n    }\r\n\r\n    @include m.tablet{\r\n        padding-block-end: 5rem;\r\n        flex-direction: column;\r\n        gap: 2.4rem;\r\n\r\n        &__cards{\r\n            max-width: 100%;\r\n            width: 100%;\r\n            gap: 1.6rem;\r\n\r\n            &--fullheight{\r\n                & > .service-card{\r\n                    justify-content: flex-start;\r\n                    height: auto;\r\n                }\r\n            }\r\n        }\r\n\r\n        .service-card__header{\r\n            grid-template-columns: 72px minmax(0, 1fr);\r\n            grid-template-areas:\r\n                \"price price\"\r\n                \"timeline timeline\"\r\n                \"icon title\";\r\n            column-gap: 1.2rem;\r\n            row-gap: 0.6rem;\r\n            align-items: start;\r\n        }\r\n\r\n        .service-card__price-tag,\r\n        .service-card__timeline-tag{\r\n            position: static;\r\n            right: auto;\r\n            text-shadow: none;\r\n            line-height: 1.25;\r\n        }\r\n\r\n        .service-card__price-tag{\r\n            grid-area: price;\r\n            justify-self: start;\r\n        }\r\n\r\n        .service-card__timeline-tag{\r\n            grid-area: timeline;\r\n            justify-self: start;\r\n            translate: none;\r\n        }\r\n\r\n        .service-card__icon{\r\n            grid-area: icon;\r\n        }\r\n\r\n        .service-card__title{\r\n            grid-area: title;\r\n            align-self: center;\r\n            margin: 0;\r\n            min-width: 0;\r\n            word-break: break-all;\r\n            // overflow-wrap: anywhere;\r\n        }\r\n    }\r\n\r\n    @include m.mobile{\r\n        padding-block-end: 3rem;\r\n        gap: 1.6rem;\r\n\r\n        &__cards{\r\n            gap: 1.2rem;\r\n\r\n            & > .service-card{\r\n                padding: 2rem;\r\n            }\r\n        }\r\n\r\n        .service-card__header{\r\n            grid-template-columns: 64px minmax(0, 1fr);\r\n            grid-template-areas:\r\n                \"price price\"\r\n                \"timeline timeline\"\r\n                \"icon title\";\r\n            column-gap: 1rem;\r\n            row-gap: 0.4rem;\r\n            align-items: start;\r\n        }\r\n\r\n        .service-card__price-tag,\r\n        .service-card__timeline-tag{\r\n            font-size: 1.4rem;\r\n        }\r\n\r\n        .service-card__icon{\r\n            width: 64px;\r\n            padding: 1.4rem;\r\n            border-radius: 1.2rem;\r\n        }\r\n\r\n        .service-card__title{\r\n            line-height: 1.1;\r\n            overflow-wrap: anywhere;\r\n        }\r\n\r\n        .service-card__numlist{\r\n            & > li{\r\n                margin-left: 1.6rem;\r\n                font-size: 1.4rem;\r\n            }\r\n        }\r\n    }\r\n}\r\n\r\n//ReadyMade Companies\r\n\r\n.companies-approaches{\r\n    padding-block: 5rem;\r\n    display: flex;\r\n    align-items: flex-start;\r\n    gap: 3rem;\r\n    // flex-flow: row wrap;\r\n    &__info{\r\n        display: flex;\r\n        flex-direction: column;\r\n        justify-content: space-around;\r\n        max-width: 50%;\r\n        gap: 3rem;\r\n        padding-block: 3rem;\r\n        &-title{\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightSemibold;\r\n        }\r\n    }\r\n    &__features{\r\n        margin: 0rem 2rem;\r\n        & > li{\r\n            margin: 1rem 0;\r\n            &::marker {\r\n                font-family: vars.$mainFontFamily;\r\n                font-weight: vars.$mainFontWeightBold;\r\n                font-size: 1.6rem;\r\n            }\r\n            & > p {\r\n                font-family: vars.$mainFontFamily;\r\n                font-weight: vars.$mainFontWeightMedium;\r\n            }\r\n        }\r\n    }\r\n    &__cards{\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 2rem;\r\n        flex: 1 1 0;\r\n        min-width: 0;\r\n        & > .service-card{\r\n            width: 100%;\r\n        }\r\n    }\r\n\r\n    @include m.tablet{\r\n        padding-block: 3rem;\r\n        flex-direction: column;\r\n        gap: 2.4rem;\r\n\r\n        &__info{\r\n            max-width: 100%;\r\n            padding-block: 0;\r\n            gap: 2rem;\r\n        }\r\n\r\n        &__features{\r\n            margin: 0 0 0 2rem;\r\n        }\r\n\r\n        &__cards{\r\n            width: 100%;\r\n            gap: 1.6rem;\r\n        }\r\n    }\r\n\r\n    @include m.mobile{\r\n        padding-block: 2rem 3rem;\r\n        gap: 2rem;\r\n\r\n        &__info{\r\n            gap: 1.6rem;\r\n\r\n            &-title{\r\n                text-align: center;\r\n                line-height: 1.1;\r\n                text-wrap: balance;\r\n            }\r\n\r\n            &-text{\r\n                line-height: 1.45;\r\n            }\r\n        }\r\n\r\n        &__features{\r\n            margin: 0 0 0 1.6rem;\r\n\r\n            & > li{\r\n                margin: 0.8rem 0;\r\n\r\n                &::marker {\r\n                    font-size: 1.4rem;\r\n                }\r\n\r\n                & > p {\r\n                    line-height: 1.4;\r\n                }\r\n            }\r\n        }\r\n\r\n        &__cards{\r\n            margin-top: 2rem;\r\n            gap: 1.4rem;\r\n            & > .service-card{\r\n                padding: 2rem;\r\n            }\r\n        }\r\n    }\r\n}\r\n\r\n//Bank Cards\r\n\r\n.bankcards-advantages{\r\n    padding-block: 2rem;\r\n    display: flex;\r\n    flex-direction: column;\r\n    justify-content: space-around;\r\n}\r\n.advantage-card{\r\n    display: flex;\r\n    flex-direction: column;\r\n    gap: 2rem;\r\n    padding: 2rem;\r\n    margin: 0.5rem 1rem;\r\n    border-radius: 2rem;\r\n    background-color: vars.$lightColor;\r\n    &__icon{\r\n        width: 6rem;\r\n    }\r\n\r\n    &__title{\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightSemibold;\r\n        font-size: 2rem;\r\n    }\r\n    &__text{\r\n        color: vars.$greyColor;\r\n        font-size: 1.6rem;\r\n\r\n    }\r\n}\r\n\r\n.cards {\r\n    &-services{\r\n        background: radial-gradient(\r\n            vars.$lightColor,\r\n            #ffffff\r\n        );\r\n        padding-block: 5rem;\r\n\r\n        & > .wrapper{ \r\n            padding-block: 5rem;\r\n            display: flex;\r\n            justify-content: space-around;\r\n        }\r\n\r\n        &__title{\r\n            text-align: center;\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightSemibold;\r\n            font-size: 5.5rem;\r\n            margin-bottom: 5rem;\r\n            color: vars.$darkColor;\r\n        }\r\n        &__card{\r\n            display: flex;\r\n            flex-direction: column;\r\n            justify-content: flex-end;\r\n            border: 1px solid vars.$borderColor;\r\n            border-radius: 2rem;\r\n            min-width: 30%;\r\n            max-width: 32%;\r\n            margin: 1rem;\r\n            background-color: #fff;\r\n            width: auto;\r\n            box-shadow: 4px 4px 20px vars.$borderColor ;\r\n            &-header{\r\n                display: flex;\r\n                justify-content: space-between;\r\n                border-radius: 2rem 2rem 0 0;\r\n                padding: 3rem 1rem;\r\n                background: linear-gradient(\r\n                    45deg,\r\n                    vars.$primaryColor,\r\n                    #185beb\r\n                );\r\n                z-index: 1;\r\n                flex-grow: 1;\r\n                \r\n                &--idbank{\r\n                    background: linear-gradient(\r\n                        45deg,\r\n                        #f5821e,\r\n                        #f8ab67\r\n                    );\r\n                }\r\n                &--amiobank{\r\n                    background: linear-gradient(\r\n                        45deg,\r\n                        #76e4f7,\r\n                        #73b4ff\r\n                    );\r\n                }\r\n                \r\n                & > img {\r\n                    width: 15rem;\r\n                    margin-left: 2rem;\r\n                }\r\n                & > .payment-systems{\r\n                    display: flex;\r\n                    flex-direction: column;\r\n                    & > img{\r\n                        width: 10rem;\r\n                        margin-right: 1rem;\r\n                    }\r\n                }\r\n            }\r\n            &-info{\r\n                display: flex;\r\n                flex-direction: column;\r\n                justify-content: space-between;\r\n                gap: 1.4rem;\r\n                padding: 1rem 2rem;\r\n            }\r\n            &-list{\r\n                & > h4{\r\n                    font-size: 1.6rem;\r\n                    font-family: vars.$mainFontFamily;\r\n                    font-weight: vars.$mainFontWeightSemibold;\r\n                    margin-bottom: 0.5rem;\r\n                }\r\n                & > li{\r\n                    display: inline-flex;\r\n                    font-size: 1.4rem;\r\n                    // outline: 1px dashed red;\r\n                    padding: 0.5rem 1rem;\r\n                    border-radius: 2em;\r\n                    margin: 0.4rem 0.2em;\r\n                    background-color: vars.$lightColor;\r\n                    font-family: vars.$mainFontFamily;\r\n                    font-weight: vars.$mainFontWeightMedium;\r\n                }\r\n            }\r\n            &-text{\r\n                color: vars.$greyColor;\r\n                text-align: justify;\r\n                font-size: 1.5rem;\r\n                line-height: 1.2;\r\n            }\r\n            & > .btn{\r\n                margin: 2rem 2rem;\r\n            }\r\n\r\n\r\n\r\n            &--popular{\r\n                position: relative;\r\n                &::before{\r\n                    text-align: center;\r\n                    vertical-align: middle;\r\n                    width: 80%;\r\n                    font-family: vars.$mainFontFamily;\r\n                    font-weight: vars.$mainFontWeightBold;\r\n                    color: vars.$secondaryColor;\r\n                    font-size: 1.5rem;\r\n                    position: absolute;\r\n                    top: 0;\r\n                    right: 50%;\r\n                    translate: 50% -90%;\r\n                    background-color: #fff;\r\n                    padding: 1rem 0;\r\n                    border-radius: 1em 1em 0 0;\r\n                    border: 1px solid vars.$borderColor;\r\n                    z-index: 0;\r\n                    content: '• КЛИЕНТЫ ВЫБИРАЮТ •'\r\n                }\r\n            }\r\n        }\r\n\r\n        @include m.tablet{\r\n            padding-block: 3rem;\r\n\r\n            & > .wrapper{\r\n                padding-block: 3rem;\r\n                flex-direction: column;\r\n                align-items: stretch;\r\n                gap: 1.6rem;\r\n            }\r\n\r\n            &__title{\r\n                margin-bottom: 3rem;\r\n            }\r\n\r\n            &__card{\r\n                min-width: 100%;\r\n                max-width: 100%;\r\n                margin: 0;\r\n\r\n                &-header{\r\n                    padding: 2.2rem 1.2rem;\r\n\r\n                    & > img{\r\n                        width: 13rem;\r\n                        margin-left: 0;\r\n                    }\r\n\r\n                    & > .payment-systems{\r\n                        & > img{\r\n                            width: 8rem;\r\n                            margin-right: 0;\r\n                        }\r\n                    }\r\n                }\r\n\r\n                &-info{\r\n                    padding: 1rem 1.6rem;\r\n                }\r\n\r\n                & > .btn{\r\n                    margin: 1.6rem;\r\n                }\r\n            }\r\n        }\r\n\r\n        @include m.mobile{\r\n            padding-block: 2rem 3rem;\r\n\r\n            & > .wrapper{\r\n                padding-block: 2rem;\r\n                gap: 1.2rem;\r\n            }\r\n\r\n            &__title{\r\n                margin-bottom: 2rem;\r\n                font-size: vars.$h3Size;\r\n                text-wrap: balance;\r\n            }\r\n\r\n            &__card{\r\n                border-radius: 1.6rem;\r\n\r\n                &-header{\r\n                    border-radius: 1.6rem 1.6rem 0 0;\r\n                    padding: 1.6rem 1rem;\r\n\r\n                    & > img{\r\n                        width: 11rem;\r\n                    }\r\n\r\n                    & > .payment-systems{\r\n                        & > img{\r\n                            width: 7rem;\r\n                        }\r\n                    }\r\n                }\r\n\r\n                &-info{\r\n                    gap: 1rem;\r\n                    padding: 1rem 1.2rem;\r\n                }\r\n\r\n                &-list{\r\n                    & > li{\r\n                        margin: 0.3rem 0.2em;\r\n                        padding: 0.45rem 0.9rem;\r\n                    }\r\n                }\r\n\r\n                &--popular{\r\n                    &::before{\r\n                        width: 88%;\r\n                        font-size: 1.3rem;\r\n                        padding: 0.8rem 0;\r\n                    }\r\n                }\r\n\r\n                & > .btn{\r\n                    width: calc(100% - 2.4rem);\r\n                    margin: 1.2rem;\r\n                }\r\n            }\r\n        }\r\n    }\r\n    &-process{\r\n        display: flex;\r\n        flex-flow: row wrap;\r\n        justify-content: space-around;\r\n        gap: 2rem;\r\n        &__info{\r\n            // outline: 1px dashed plum;\r\n            max-width: 50%;\r\n        }\r\n        &__title{\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightSemibold;\r\n            margin: 8rem auto;\r\n            color: vars.$darkColor;\r\n        }\r\n        &__subtitle{\r\n            font-size: 2rem;\r\n            padding: 1rem 1rem 0 1rem;\r\n        }\r\n\r\n        @include m.tablet{\r\n            padding-block: 3rem;\r\n            flex-direction: column;\r\n            align-items: stretch;\r\n            gap: 2.4rem;\r\n\r\n            &__title{\r\n                margin: 4rem auto 0;\r\n                text-align: center;\r\n            }\r\n\r\n            &__info{\r\n                max-width: 100%;\r\n            }\r\n\r\n            &__subtitle{\r\n                padding: 0;\r\n            }\r\n\r\n            &__container{\r\n                max-width: 100%;\r\n                width: 100%;\r\n            }\r\n        }\r\n\r\n        @include m.mobile{\r\n            padding-block: 2rem 3rem;\r\n            gap: 2rem;\r\n\r\n            &__title{\r\n                margin: 2rem auto 0;\r\n            }\r\n\r\n            &__subtitle{\r\n                font-size: 1.8rem;\r\n                text-align: center;\r\n            }\r\n\r\n            .bankcards-advantages{\r\n                padding-block: 1rem;\r\n                gap: 1.2rem;\r\n            }\r\n\r\n            .advantage-card{\r\n                margin: 0;\r\n                padding: 1.8rem;\r\n                gap: 1.4rem;\r\n            }\r\n        }\r\n    }\r\n}\r\n\r\n\r\n// Accounting Services\r\n.accounting{\r\n    &-details{\r\n        display: flex;\r\n        flex-flow: row wrap;\r\n        justify-content: space-around;\r\n        padding-block: 5rem;\r\n        gap: 4rem;\r\n        & > ul{ & > li{font-size: 5rem}}\r\n        &__title{\r\n            width: 100%;\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightMedium;\r\n            text-align: center;\r\n            margin-bottom: 3rem;\r\n        }\r\n        &__text{\r\n            text-align:justify; \r\n            border: 1px solid #fff;\r\n            background-color: #ffffff9c;\r\n            border-radius: 2rem;\r\n            backdrop-filter: blur(12px);\r\n            padding: 2rem;\r\n            line-height: 1.33;\r\n\r\n        }\r\n        & > .service-card--base{\r\n            max-width: 48%;\r\n            @include m.mobile{\r\n                max-width: 100%;\r\n            }\r\n        }\r\n        @include m.mobile{\r\n            gap: 1rem;\r\n        }\r\n    }\r\n    &-process{\r\n        display: flex; flex-direction: column;\r\n        gap: 10rem;\r\n        padding-block: 5rem;\r\n        &__title{\r\n            text-align: center;\r\n        }\r\n        & > .scheme-container{\r\n            max-width: 100%;\r\n        }\r\n        @include m.mobile{\r\n            gap: 3rem;\r\n            padding-block-start: 1rem;\r\n        }\r\n    }\r\n    &__price-tag{\r\n        width: 100%;\r\n        text-align: start;\r\n    }\r\n\r\n    &-animation{\r\n        &-pos1{\r\n            top:700px\r\n        }\r\n        &-pos2{\r\n            top:1550px;\r\n        }\r\n    }\r\n    @include m.mobile{\r\n        &__price-tag{\r\n            text-align: center;\r\n            text-shadow: 0 0 4px vars.$lightColor;\r\n            font-size: vars.$h5Size;\r\n        }\r\n        &-details{\r\n            &__title{\r\n                margin: 0 0 1rem 0;\r\n            }\r\n        }\r\n    }\r\n}\r\n\r\n.bg-geometry{\r\n    position: absolute;\r\n    right: -360px;\r\n    height: 350px;\r\n    min-width: 350px;\r\n    border-radius: 2rem;\r\n    background: linear-gradient(\r\n        45deg,\r\n        vars.$primaryColor,\r\n        vars.$secondaryColor\r\n    );\r\n}\r\n.bg-geometry-2{\r\n    translate: -100% 0;\r\n    left: 0;\r\n    position: absolute;\r\n    height: 350px;\r\n    min-width: 350px;\r\n    border-radius: 2rem;\r\n    background: linear-gradient(\r\n        45deg,\r\n        vars.$primaryColor,\r\n        vars.$secondaryColor\r\n    );\r\n}\r\n\r\n.bg-geometry-cubeBase{\r\n    position: absolute;\r\n    top: 0;\r\n    width: 250px;\r\n    height: 700px;\r\n    border-radius: 2rem;\r\n    background: linear-gradient(\r\n        45deg,\r\n        vars.$primaryColor,\r\n        vars.$secondaryColor\r\n    );\r\n}\r\n\r\n\r\n\r\n// REGISTRATION\r\n.registration{\r\n    &-details{\r\n    display: flex;\r\n    flex-direction: column;\r\n    gap: 10rem;\r\n    padding-block: 5rem;\r\n        & > .scheme-container--horizontal{\r\n            max-width: 100%;\r\n        }\r\n        &__title{\r\n            text-align: center;\r\n        }\r\n\r\n        @include m.tablet{\r\n            gap: 2.6rem;\r\n            padding-block: 3rem;\r\n        }\r\n\r\n        @include m.mobile{\r\n            gap: 1.8rem;\r\n            padding-block: 2rem 3rem;\r\n\r\n            &__title{\r\n                text-wrap: balance;\r\n            }\r\n        }\r\n    }\r\n    &-methods{\r\n        padding-block: 5rem;\r\n        display: flex;\r\n        gap: 2rem;\r\n\r\n        @include m.tablet{\r\n            padding-block: 3rem;\r\n            display: grid;\r\n            grid-template-columns: 1fr;\r\n            gap: 1.6rem;\r\n\r\n            & > .service-card{\r\n                margin: 0;\r\n                width: 100%;\r\n                min-width: 0;\r\n                height: auto;\r\n                padding: 2.4rem;\r\n            }\r\n\r\n            .service-card__header{\r\n                grid-template-columns: 72px minmax(0, 1fr);\r\n                grid-template-areas:\r\n                    \"price price\"\r\n                    \"timeline timeline\"\r\n                    \"icon title\";\r\n                column-gap: 1.2rem;\r\n                row-gap: 0.6rem;\r\n                align-items: start;\r\n            }\r\n\r\n            .service-card__price-tag,\r\n            .service-card__timeline-tag{\r\n                position: static;\r\n                right: auto;\r\n                text-shadow: none;\r\n            }\r\n\r\n            .service-card__price-tag{\r\n                grid-area: price;\r\n                justify-self: start;\r\n            }\r\n\r\n            .service-card__timeline-tag{\r\n                grid-area: timeline;\r\n                justify-self: start;\r\n                translate: none;\r\n            }\r\n\r\n            .service-card__icon{\r\n                grid-area: icon;\r\n            }\r\n\r\n            .service-card__title{\r\n                grid-area: title;\r\n                margin: 0;\r\n                align-self: center;\r\n                min-width: 0;\r\n                overflow-wrap: anywhere;\r\n            }\r\n        }\r\n\r\n        @include m.mobile{\r\n            padding-block: 2rem 3rem;\r\n            gap: 1.2rem;\r\n\r\n            & > .service-card{\r\n                padding: 2rem;\r\n            }\r\n\r\n            .service-card__header{\r\n                grid-template-columns: 64px minmax(0, 1fr);\r\n                column-gap: 1rem;\r\n                row-gap: 0.4rem;\r\n            }\r\n\r\n            .service-card__price-tag,\r\n            .service-card__timeline-tag{\r\n                font-size: 1.4rem;\r\n            }\r\n\r\n            .service-card__icon{\r\n                width: 64px;\r\n                padding: 1.4rem;\r\n                border-radius: 1.2rem;\r\n            }\r\n\r\n            .service-card__cta > .btn{\r\n                width: 100%;\r\n            }\r\n        }\r\n    }\r\n}\r\n\r\n\r\n//playground\r\n.sandbox{\r\n    height: 600vh; \r\n    display: flex; flex-flow: row wrap;\r\n    align-content: flex-start;\r\n    justify-content: space-between;\r\n    padding: 10rem; \r\n    border: 1px dashed rgb(141, 176, 216); \r\n    border-radius: 2rem; \r\n    margin-bottom: 2rem;\r\n}\r\n.playground-box{\r\n    width: 85px;\r\n    height: 85px;\r\n    background: radial-gradient(\r\n        #1596d1,\r\n        #4740aa\r\n    );\r\n    border-radius: 2em;\r\n    margin: 1rem 0.5rem;\r\n}\r\n\r\n.bg-animations{\r\n    height: 10px;\r\n    width: 100%;\r\n    position: relative;\r\n    overflow-x: clip;\r\n    z-index: -10;\r\n}\r\n\r\n\r\n//maintenance\r\n\r\n.maintenance{\r\n    &-container{\r\n        // outline: 2px dashed salmon;\r\n        height: 100vh;\r\n        display: flex;\r\n        flex-direction: column;\r\n        justify-content: space-between;\r\n    }\r\n    &__logo{\r\n        align-self: flex-start;\r\n        margin-top: 2rem;\r\n        width: 200px;\r\n        display: flex;\r\n        margin-inline: auto;\r\n    }\r\n    &__title{\r\n        text-align: center;\r\n        margin: 1rem 0;\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightBold;\r\n        @include m.mobile{\r\n            font-size: 3rem;\r\n            margin-bottom: 4rem;\r\n        }\r\n    }\r\n    &__subtitle{\r\n        text-align: center;\r\n        margin: 1rem 0;\r\n\r\n        @include m.mobile{\r\n            font-size: 1.4rem;\r\n\r\n        }\r\n    }\r\n    &__mid{\r\n        & > h5{\r\n            margin-top: 2rem;\r\n        }\r\n    }\r\n    &__end{\r\n        text-align: center;\r\n        margin-bottom: 3rem;\r\n    }\r\n    &__bg-design{\r\n        position: absolute;\r\n        z-index: -100;\r\n        height: 100vh;\r\n        width: 100vw;\r\n        overflow: hidden;\r\n        &__item{\r\n            position: absolute;\r\n            width: 700px;\r\n            height: 700px;\r\n            background: radial-gradient(vars.$primaryColor, vars.$secondaryColor 70%);\r\n            border-radius: 100%;\r\n            &:nth-child(1) {\r\n                top: -400px;\r\n                left: -300px;\r\n            }\r\n            &:nth-child(2) {\r\n                position: absolute;\r\n                right: -380px;\r\n                bottom: -380px;;\r\n                // translate: 30% 30%;\r\n            }\r\n        }\r\n    }\r\n    &__contact-links{\r\n        margin-top: 3rem;\r\n        display: flex;\r\n        justify-content: space-around;\r\n        & > ul {\r\n            background-color: #fff;\r\n            border: 1px solid vars.$borderColor;\r\n            padding: 2rem;\r\n            border-radius: 2rem;\r\n            & > p{\r\n                margin-bottom: 1rem;\r\n            }\r\n        }\r\n    }\r\n    &__lang-switcher{\r\n        right: 0;\r\n        position: absolute;\r\n        display: flex;\r\n        justify-content: center;\r\n        & > button{\r\n            margin: 1rem;\r\n            & > img{\r\n                margin-left: 1rem;\r\n            }\r\n        }\r\n    }\r\n}\r\n.sassafras{\r\n    padding: 2rem 0 0 0;\r\n}\r\n\r\n\r\n// ABOUT-US & STAFF\r\n\r\n.about-us-page{\r\n    @include m.mobile{\r\n        & > .hero--aboutus,\r\n        & > .staff,\r\n        & > .reviews,\r\n        & > .contact{\r\n            padding-inline: 2rem;\r\n        }\r\n    }\r\n}\r\n\r\n.staff{\r\n    display: flex;\r\n    flex-wrap: wrap;\r\n    padding-block: 5rem;\r\n    gap: 3rem;\r\n    background: linear-gradient(\r\n        180deg,\r\n        #DFEDFF,\r\n        #ffffff\r\n    ); \r\n    &__header{\r\n        width: 100%;\r\n        text-align: center;\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightSemibold;\r\n    }\r\n    &-container{\r\n        display: flex;\r\n        flex-flow: row wrap;\r\n        justify-content: space-around;\r\n        gap: 3.5rem;\r\n        @extend .wrapper;\r\n        padding: 0;\r\n    }\r\n    &-card{\r\n        width: 290px;\r\n        display: flex;\r\n        flex-direction: column;\r\n        gap: 1.5rem;\r\n        outline: 1px solid vars.$borderColor;\r\n        padding: 2rem;\r\n        border-radius: 3rem;\r\n        background-color: #ffffff7a;\r\n        &__header{\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightSemibold;\r\n            text-align: center;    \r\n        }\r\n        &__position{\r\n            text-align: center;\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightMedium;\r\n        }\r\n        &__photo{\r\n            width: 250px;\r\n            border-radius: 2rem;\r\n        }\r\n    }\r\n\r\n    @include m.mobile{\r\n        gap: 2rem;\r\n        padding-block: 3rem;\r\n\r\n        &-container{\r\n            gap: 2rem;\r\n            justify-content: center;\r\n        }\r\n\r\n        &-card{\r\n            width: 100%;\r\n            max-width: 29rem;\r\n            padding: 1.6rem;\r\n\r\n            &__photo{\r\n                width: 100%;\r\n                max-width: 25rem;\r\n                align-self: center;\r\n            }\r\n        }\r\n    }\r\n}\r\n\r\n// CONTACTS PAGE\r\n\r\n.extra-details{\r\n    display: flex;\r\n    justify-content: space-between;\r\n    flex-flow: row wrap;\r\n    gap: 3rem;\r\n    padding-block-end: 10rem;\r\n    &__text{\r\n        text-align: center;\r\n    }\r\n    &__container{\r\n        // outline: 1px dashed salmon;\r\n        width: 48%;\r\n        display: flex;\r\n        flex-flow:column wrap;\r\n        align-items: center;\r\n        gap: 3rem;\r\n        &-item{\r\n            display: flex;\r\n            flex-direction: column;\r\n            align-items: center;\r\n            gap: 1rem;\r\n        }\r\n        &-wrapper{\r\n            display: flex;\r\n            justify-content: space-around;\r\n            width: 100%;\r\n            // outline: 1px dashed pink;\r\n            margin: 0 auto;\r\n        }\r\n        & > h3, h5{\r\n            text-align: center;\r\n        }\r\n        & > video{\r\n            display: block;\r\n            width: 100%;\r\n            height: auto;\r\n            aspect-ratio: 1920 / 1080;\r\n            border-radius: 1rem;\r\n            border: 2px solid vars.$primaryColor;  \r\n        }\r\n    }\r\n    &__iframe{\r\n        border-radius: 1rem;\r\n        border: 2px solid vars.$primaryColor; \r\n        width: 100%;\r\n        min-height: 337px;\r\n\r\n    }\r\n    &__map-link{\r\n        background-color: #ffffffcb;\r\n        gap: 2rem;\r\n        display: flex;\r\n        flex-direction: column;\r\n        font-size: vars.$h4Size;\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightSemibold;\r\n        text-align: center;\r\n        padding: 2rem;\r\n        transition: 0.23s;\r\n        border-radius: 1rem;\r\n        border: 1px solid vars.$borderColor;\r\n        // border: 1px solid #fff;\r\n        &:hover{\r\n            box-shadow: 0 0 20px vars.$lightColor;\r\n            scale: 1.05;\r\n            border: 1px solid #fff;\r\n        }\r\n    }\r\n    &__map-image{\r\n        width: 70px;\r\n        height: 70px;\r\n        display: block;\r\n        align-self: center;\r\n        margin-inline: auto;\r\n    }\r\n\r\n    @include m.tablet{\r\n        gap: 3rem;\r\n        padding-block-end: 6rem;\r\n\r\n        &__container{\r\n            width: 100%;\r\n            gap: 2rem;\r\n            & > video{\r\n                width: 100%;\r\n            }\r\n        }\r\n\r\n        // &__iframe{\r\n        //     min-height: 34rem;\r\n        // }\r\n\r\n        &__map-link{\r\n            font-size: 2rem;\r\n            padding: 1.6rem;\r\n        }\r\n\r\n        &__map-image{\r\n            width: 60px;\r\n            height: 60px;\r\n        }\r\n    }\r\n\r\n    @include m.mobile{\r\n        gap: 2rem;\r\n        padding-block-end: 4rem;\r\n\r\n        &__container{\r\n            gap: 1.6rem;\r\n            & > video{\r\n                width: 100%;\r\n            }\r\n        }\r\n\r\n        &__text{\r\n            text-align: start;\r\n        }\r\n\r\n        &__iframe{\r\n            height: 20rem;\r\n        }\r\n\r\n        &__map-link{\r\n            width: 100%;\r\n            font-size: 1.8rem;\r\n            padding: 1.2rem;\r\n            gap: 1rem;\r\n        }\r\n\r\n        &__map-image{\r\n            width: 52px;\r\n            height: 52px;\r\n        }\r\n    }\r\n}\r\n\r\n// REVIEWS\r\n\r\n.reviews{\r\n    padding-block: 3rem 10rem;\r\n    &__title, &__text{\r\n        text-align:center;\r\n        margin: 2rem;\r\n    }\r\n    &__text{\r\n        line-height: 1.3;\r\n    }\r\n    &__title{\r\n        font-family: vars.$mainFontFamily;\r\n        font-weight: vars.$mainFontWeightMedium;\r\n    }\r\n    \r\n    @include m.mobile{\r\n        &__title{\r\n            font-family: vars.$mainFontFamily;\r\n            font-weight: vars.$mainFontWeightSemibold;\r\n        }\r\n    }\r\n\r\n}\r\n\r\n// SWIPER\r\n\r\n.swiper{\r\n    height: 35rem;\r\n    width: 80%;\r\n    &-slide{\r\n        display: flex;\r\n        justify-content: center;\r\n        align-items: center;\r\n        font-size: vars.$h3Size;\r\n        font-family: vars.$mainFontRegular;\r\n        border-radius: 2rem;\r\n        &__card{\r\n            background-color: #fff;\r\n            width: 70%;\r\n            padding: 2rem;\r\n            display: flex;\r\n            flex-flow: row wrap;\r\n            justify-content: flex-start;\r\n            border: 1px solid vars.$borderColor;\r\n            border-radius: 1.5rem;\r\n            box-shadow: 0px 0px 15px vars.$blueShadowColor;\r\n            & > header{\r\n                display: flex;\r\n                flex-direction: column;\r\n                justify-content: center;\r\n                align-items: flex-start;\r\n                // outline: 1px solid red;\r\n                gap: 1rem;\r\n            }\r\n            &-name{\r\n                font-family: vars.$mainFontFamily;\r\n                font-weight: vars.$mainFontWeightSemibold;\r\n            }\r\n            &-date{\r\n                font-family: vars.$mainFontFamily;\r\n                font-weight: vars.$mainFontWeightMedium;\r\n            }\r\n            &-stars{\r\n                left: 0;\r\n                // outline: 1px solid rgb(136, 160, 49);\r\n                height: 30px;\r\n                // width: 80%;\r\n                content: url(/src/graphics/svg/card-stars.svg);\r\n            }\r\n            &-image{\r\n                width: 100px;\r\n                height: 100px;\r\n                margin: 2rem;\r\n                border-radius: 100%;\r\n                border: 1px solid vars.$borderColor;\r\n            }\r\n            &-text{\r\n                margin: 1rem 2rem;\r\n            }\r\n        }\r\n    }\r\n    &-button-next, &-button-prev{\r\n        border-radius: 100%;\r\n        transition: 0.33s;\r\n        &:hover{\r\n            scale: 1.2;\r\n            filter: brightness(1.5);\r\n        }\r\n    }\r\n    \r\n    @include m.mobile{\r\n        height: 60rem;\r\n        width: 100%;\r\n        &-button-next, &-button-prev{\r\n            scale: 0.3;\r\n            &:hover{\r\n                scale: 0.7;\r\n            }\r\n        }\r\n        &-slide{\r\n            &__card{\r\n                width: 100%;\r\n                min-height: 40rem;\r\n                &-image, &-name, &-date, &-stars, & > header{\r\n                    margin: auto;\r\n                    text-align: center;\r\n                }\r\n                &-text{\r\n                    margin: 2rem 2rem;\r\n                    text-align: justify;\r\n                }\r\n            }\r\n        }\r\n    }\r\n}"]}
